  { id: ToolType.IDEAS, label: 'Idea Generator', icon: <Lightbulb size={18} />, category: 'Creative' },
  { id: ToolType.SCRIPT, label: 'Script Writer', icon: <FileText size={18} />, category: 'Creative' },
  { id: ToolType.VIDEO, label: 'Video Studio', icon: <Video size={18} />, category: 'Creative' },
  { id: ToolType.AUDIO, label: 'Audio Studio', icon: <Mic size={18} />, category: 'Creative' },
  { id: ToolType.THUMBNAIL, label: 'Thumbnail Studio', icon: <ImageIcon size={18} />, category: 'Creative' },

