  { id: ToolType.KEYWORD_INSPECTOR, label: 'Keyword Inspector', icon: <Tag size={18} />, category: 'Growth' },
  { id: ToolType.TREND_WATCHER, label: 'Trend Watcher', icon: <TrendingUp size={18} />, category: 'Growth' },
  { id: ToolType.COMPETITOR_SPY, label: 'Competitor Spy', icon: <Search size={18} />, category: 'Growth' },

  { id: ToolType.OUTREACH, label: 'Outreach Hub', icon: <Users size={18} />, category: 'Outreach' },
  { id: ToolType.EMAIL_MARKETING, label: 'Email Blast', icon: <Mail size={18} />, category: 'Outreach' },
  { id: ToolType.MARKET_STRATEGIST, label: 'Market Strategist', icon: <LineChart size={18} />, category: 'Outreach' },

  { id: ToolType.REPURPOSE, label: 'Repurpose Engine', icon: <Repeat size={18} />, category: 'Automation' },
  { id: ToolType.MARKETING, label: 'Marketing Scheduler', icon: <Search size={18} />, category: 'Automation' },
