export const Layout: React.FC<LayoutProps> = ({ currentTool, onNavigate, children }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = React.useState(false);
  const [searchQuery, setSearchQuery] = React.useState('');
  const { user, logout, checkPlanStatus } = useAuth();
  const { daysLeft, isFree } = checkPlanStatus();

  const categories = Array.from(new Set(NAV_ITEMS.map(i => i.category || 'Other')));

  const filteredTools = NAV_ITEMS.filter(item => 
    item.label.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="flex h-screen bg-[#09090b] text-white overflow-hidden font-sans">
      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex w-64 flex-col border-r border-zinc-800 bg-[#0f0f12]">
        <div className="p-6">
          <h1 className="text-2xl font-bold bg-gradient-to-r from-red-500 to-orange-500 bg-clip-text text-transparent">
            Ranktica AI
          </h1>
          <p className="text-[10px] text-zinc-500 font-bold uppercase tracking-widest mt-1">Creator Suite</p>
        </div>

        <nav className="flex-1 px-3 space-y-4 overflow-y-auto pb-6 custom-scrollbar">
          {categories.map(cat => (
            <div key={cat} className="space-y-1">
              <h3 className="px-4 text-[10px] font-bold text-zinc-600 uppercase tracking-widest mb-1 mt-4">{cat}</h3>
              {NAV_ITEMS.filter(i => i.category === cat).map((item) => (
                <button
                  key={item.id}
                  onClick={() => onNavigate(item.id)}
                  className={`flex items-center w-full px-4 py-2 text-sm font-medium rounded-xl transition-all duration-300 active-press ${
                    currentTool === item.id 
                      ? 'bg-red-500/10 text-red-500 border border-red-500/20 shadow-lg shadow-red-500/5' 
                      : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-white border border-transparent'
                  }`}
                >
                  <span className={`mr-3 transition-transform duration-300 ${currentTool === item.id ? 'scale-110' : 'group-hover:scale-110'}`}>
                    {item.icon}
                  </span>
                  {item.label}
                </button>
              ))}
            </div>
          ))}
        </nav>

        {/* User Profile & Plan Status */}
        <div className="p-4 border-t border-zinc-800 space-y-4">
           <div className="flex flex-col gap-2 p-3 rounded-2xl bg-zinc-900/50 border border-zinc-800 hover:border-zinc-700 transition-colors group cursor-default">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold text-xs transition-transform duration-300 group-hover:rotate-3 ${isFree ? 'bg-zinc-700 text-zinc-300' : 'bg-gradient-to-tr from-blue-500 to-purple-500 text-white shadow-lg shadow-blue-500/20'}`}>
                  {isFree ? 'FREE' : 'PRO'}
                </div>
                <div className="flex-1 overflow-hidden">
                   <p className="text-sm font-bold truncate group-hover:text-white transition-colors">{user?.name}</p>
                   <p className="text-[10px] text-zinc-500 font-medium">{daysLeft} days remaining</p>
                </div>
              </div>
           </div>

           <button 
             onClick={logout}
             className="w-full flex items-center justify-center gap-2 text-sm text-zinc-500 hover:text-red-400 transition-all py-2 rounded-xl hover:bg-red-500/5"
           >
             <LogOut size={16} /> Sign Out
           </button>
        </div>
      </aside>

      {/* Mobile Header */}
      <div className="md:hidden fixed top-0 w-full z-50 bg-[#0f0f12]/80 backdrop-blur-md border-b border-zinc-800 px-4 py-3 flex items-center justify-between">
         <h1 className="text-xl font-bold text-red-500">Ranktica AI</h1>
         <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} className="p-2 text-zinc-400 active-press">
            {isMobileMenuOpen ? <X /> : <Menu />}
         </button>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col relative overflow-hidden pt-16 md:pt-0 bg-[#09090b]">
        {/* Desktop Header with Search */}
        <header className="hidden md:flex items-center justify-between px-8 py-4 border-b border-zinc-800 bg-[#0f0f12]/80 backdrop-blur-md sticky top-0 z-30">
            <div className="flex items-center text-sm font-medium text-zinc-400">
               <span className="hover:text-white cursor-pointer transition-colors" onClick={() => onNavigate(ToolType.DASHBOARD)}>Ranktica AI</span>
               <ChevronRight size={14} className="mx-2 text-zinc-600" />
               <span className="text-white bg-zinc-800/80 px-3 py-1 rounded-lg text-xs font-bold animate-scale-in">
                 {NAV_ITEMS.find(n => n.id === currentTool)?.label || 'Dashboard'}
               </span>
            </div>

            <div className="relative group z-50">
               <div className="relative">
                  <Search className={`absolute left-4 top-1/2 -translate-y-1/2 transition-colors duration-300 ${searchQuery ? 'text-red-500' : 'text-zinc-500'}`} size={16} />
                  <input 
                      type="text"
                      placeholder="Search tools..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="w-64 focus:w-80 bg-zinc-900/50 border border-zinc-800 hover:border-zinc-700 focus:border-red-500/50 rounded-2xl pl-11 pr-4 py-2 text-sm text-white outline-none transition-all placeholder:text-zinc-600"
                  />
               </div>
               {searchQuery && (
                  <div className="absolute top-full right-0 mt-3 w-80 bg-[#0f0f12] border border-zinc-800 rounded-2xl shadow-2xl overflow-hidden z-50 animate-fade-in glass-morphism">
                      <div className="p-2 border-b border-zinc-800 text-[10px] font-bold text-zinc-500 uppercase tracking-widest px-4">Search Results</div>
                      <div className="max-h-[400px] overflow-y-auto custom-scrollbar">
                        {filteredTools.length > 0 ? filteredTools.map(item => (
                            <button
                                key={item.id}
                                onClick={() => {
                                    onNavigate(item.id);
                                    setSearchQuery('');
                                }}
                                className="w-full text-left px-4 py-3 hover:bg-red-500/10 flex items-center gap-3 transition-all group border-b border-zinc-800/50 last:border-0"
                            >
                                <span className="text-zinc-400 group-hover:text-red-500 transition-colors">{item.icon}</span>
                                <span className="text-zinc-300 group-hover:text-white text-sm font-medium transition-colors">{item.label}</span>
                            </button>
                        )) : (
                          <div className="p-4 text-center text-zinc-600 text-xs italic">No tools found</div>
                        )}
                      </div>
                  </div>
               )}
            </div>
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar">
          <div className="max-w-6xl mx-auto h-full">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

import React from 'react';
import { VideoIdea } from '../types';
import { Sparkles, Copy, Check } from 'lucide-react';

interface IdeaCardProps {
  idea: VideoIdea;
}

export const IdeaCard: React.FC<IdeaCardProps> = ({ idea }) => {
  const [copied, setCopied] = React.useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(`${idea.title}\n${idea.hook}`);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="group relative bg-zinc-900 border border-zinc-800 p-6 rounded-[2rem] transition-all duration-300 hover:border-red-500/40 hover:shadow-2xl hover:shadow-red-500/5 animate-scale-in hover-lift">
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-2">
           <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
             idea.score >= 8 ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 
             idea.score >= 6 ? 'bg-yellow-500/10 text-yellow-400 border border-yellow-500/20' : 
             'bg-red-500/10 text-red-400 border border-red-500/20'
           }`}>
             Viral Potential: {idea.score}/10
           </span>
        </div>
        <button 
          onClick={handleCopy}
          className={`p-2.5 rounded-xl transition-all active-press ${copied ? 'bg-green-500/10 text-green-500' : 'bg-zinc-800 text-zinc-500 hover:text-white hover:bg-zinc-700'}`}
          title="Copy Idea"
        >
          {copied ? <Check size={16} /> : <Copy size={16} />}
        </button>
      </div>

      <h3 className="text-xl font-extrabold text-white mb-3 group-hover:text-red-500 transition-colors duration-300 leading-tight">
        {idea.title}
      </h3>

      <div className="flex gap-3 items-start mt-4 p-4 bg-zinc-950 border border-zinc-800 rounded-2xl group-hover:bg-zinc-900 transition-colors">
        <div className="p-2 bg-purple-500/10 rounded-lg shrink-0">
          <Sparkles size={16} className="text-purple-400" />
        </div>
        <p className="text-sm text-zinc-400 leading-relaxed">
          <span className="font-bold text-zinc-300 uppercase text-[10px] tracking-wider block mb-1">Viral Hook:</span> 
          {idea.hook}
        </p>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Project } from '../types';
import { 
  Plus, 
  MoreHorizontal, 
  Calendar, 
  FileText, 
  Image as ImageIcon, 
  Search, 
  Video, 
  Users, 
  Share2, 
  Check, 
  Link as LinkIcon,
  Trash2,
  X as XIcon,
  Copy as CopyIcon,
  ChevronRight
} from 'lucide-react';

export const Projects: React.FC = () => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [isCreating, setIsCreating] = useState(false);
  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectNiche, setNewProjectNiche] = useState('');

  const [shareProject, setShareProject] = useState<Project | null>(null);
  const [copiedLink, setCopiedLink] = useState(false);
  const [inviteEmail, setInviteEmail] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('ranktica_projects');
    if (saved) {
      setProjects(JSON.parse(saved));
    } else {
      const dummies: Project[] = [
        {
          id: '1',
          title: 'Summer Vlog 2025',
          niche: 'Vlog',
          status: 'production',
          lastUpdated: Date.now(),
          assets: { script: true, thumbnail: true, video: false, seo: true },
          team: ['https://randomuser.me/api/portraits/men/32.jpg']
        },
        {
          id: '2',
          title: 'AI Tool Review',
          niche: 'Tech',
          status: 'idea',
          lastUpdated: Date.now() - 86400000,
          assets: { script: false, thumbnail: false, video: false, seo: false },
          team: []
        },
        {
          id: '3',
          title: 'How to Bake Bread',
          niche: 'Cooking',
          status: 'published',
          lastUpdated: Date.now() - 100000000,
          assets: { script: true, thumbnail: true, video: true, seo: true },
          team: ['https://randomuser.me/api/portraits/women/44.jpg', 'https://randomuser.me/api/portraits/men/11.jpg']
        }
      ];
      setProjects(dummies);
    }
  }, []);

  const saveProjects = (updated: Project[]) => {
    setProjects(updated);
    localStorage.setItem('ranktica_projects', JSON.stringify(updated));
  };

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return;

    const newProject: Project = {
      id: Date.now().toString(),
      title: newProjectName,
      niche: newProjectNiche || 'General',
      status: 'idea',
      lastUpdated: Date.now(),
      assets: {},
      team: []
    };

    saveProjects([newProject, ...projects]);
    setIsCreating(false);
    setNewProjectName('');
    setNewProjectNiche('');
  };

  const updateStatus = (id: string, newStatus: Project['status']) => {
    const updated = projects.map(p => p.id === id ? { ...p, status: newStatus, lastUpdated: Date.now() } : p);
    saveProjects(updated);
  };

  const handleDelete = (id: string) => {
    if (confirm("Are you sure you want to delete this project?")) {
      saveProjects(projects.filter(p => p.id !== id));
    }
  };

  const handleCopyLink = () => {
    navigator.clipboard.writeText(`https://ranktica.ai/p/${shareProject?.id}/share?token=xyz123`);
    setCopiedLink(true);
    setTimeout(() => setCopiedLink(false), 2000);
  };

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (inviteEmail && shareProject) {
      alert(`Invitation sent to ${inviteEmail}`);
      setInviteEmail('');
      setShareProject(null);
    }
  };

  const columns = [
    { id: 'idea', label: 'Idea Phase', color: 'bg-zinc-500' },
    { id: 'scripting', label: 'Scripting', color: 'bg-blue-500' },
    { id: 'production', label: 'Production', color: 'bg-orange-500' },
    { id: 'scheduled', label: 'Scheduled', color: 'bg-purple-500' },
    { id: 'published', label: 'Published', color: 'bg-green-500' }
  ];

  return (
    <div className="h-full flex flex-col space-y-8 animate-fade-in pb-10">
      <div className="flex justify-between items-center shrink-0">
         <div>
            <h2 className="text-3xl font-extrabold text-white tracking-tight">Project Board</h2>
            <p className="text-zinc-400">Streamline your production workflow across the team.</p>
         </div>
         <button 
           onClick={() => setIsCreating(true)}
           className="bg-red-600 hover:bg-red-500 text-white px-6 py-3 rounded-2xl font-bold shadow-lg shadow-red-600/20 flex items-center gap-2 active-press transition-all"
         >
           <Plus size={20} /> Create New
         </button>
      </div>

      {isCreating && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
           <form onSubmit={handleCreate} className="bg-zinc-900 border border-zinc-800 rounded-[2rem] p-10 w-full max-w-md shadow-2xl ring-1 ring-white/10">
              <h3 className="text-2xl font-extrabold text-white mb-6">Initialize Project</h3>
              <div className="space-y-6">
                 <div>
                    <label className="text-xs font-bold text-zinc-500 uppercase block mb-2 tracking-widest">Project Title</label>
                    <input 
                      value={newProjectName}
                      onChange={e => setNewProjectName(e.target.value)}
                      placeholder="e.g. 50 Days in Antarctica"
                      className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl p-4 text-white focus:ring-2 focus:ring-red-500/50 outline-none transition-all"
                      autoFocus
                    />
                 </div>
                 <div>
                    <label className="text-xs font-bold text-zinc-500 uppercase block mb-2 tracking-widest">Niche / Target Market</label>
                    <input 
                      value={newProjectNiche}
                      onChange={e => setNewProjectNiche(e.target.value)}
                      placeholder="e.g. Travel / Adventure"
                      className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl p-4 text-white focus:ring-2 focus:ring-red-500/50 outline-none transition-all"
                    />
                 </div>
                 <div className="flex gap-4 mt-8">
                    <button type="button" onClick={() => setIsCreating(false)} className="flex-1 py-3 text-zinc-400 hover:text-white font-bold transition-colors">Cancel</button>
                    <button type="submit" disabled={!newProjectName} className="flex-[2] bg-red-600 hover:bg-red-500 text-white rounded-2xl font-extrabold shadow-lg shadow-red-600/20 active-press transition-all">Start Project</button>
                 </div>
              </div>
           </form>
        </div>
      )}

      {/* Share Modal */}
      {shareProject && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
           <div className="bg-zinc-900 border border-zinc-800 rounded-[2rem] p-10 w-full max-w-md shadow-2xl ring-1 ring-white/10">
              <div className="flex justify-between items-start mb-8">
                 <div>
                   <h3 className="text-2xl font-extrabold text-white">Share Access</h3>
                   <p className="text-sm text-zinc-400 mt-1">Collaborate on "{shareProject.title}"</p>
                 </div>
                 <button onClick={() => setShareProject(null)} className="p-2 hover:bg-zinc-800 rounded-full text-zinc-500 transition-colors"><XIcon size={24} /></button>
              </div>

              <div className="space-y-8">
                 <div>
                    <label className="text-[10px] font-black text-zinc-500 uppercase block mb-2 tracking-widest">Direct Invite</label>
                    <form onSubmit={handleInvite} className="flex gap-3">
                       <input 
                         type="email" 
                         value={inviteEmail}
                         onChange={e => setInviteEmail(e.target.value)}
                         placeholder="collab@example.com"
                         className="flex-1 bg-zinc-950 border border-zinc-800 rounded-xl p-3 text-white text-sm outline-none focus:border-blue-500 transition-all"
                       />
                       <button type="submit" className="bg-blue-600 hover:bg-blue-500 text-white px-6 rounded-xl text-sm font-bold shadow-lg shadow-blue-500/20 active-press transition-all">Invite</button>
                    </form>
                 </div>

                 <div>
                    <label className="text-[10px] font-black text-zinc-500 uppercase block mb-2 tracking-widest">Workspace Link</label>
                    <div className="flex gap-2 bg-zinc-950 border border-zinc-800 p-3 rounded-2xl">
                       <div className="flex-1 text-sm text-zinc-500 truncate flex items-center gap-2">
                          <LinkIcon size={14} className="text-zinc-700" />
                          ranktica.ai/p/{shareProject.id}/share...
                       </div>
                       <button onClick={handleCopyLink} className="text-zinc-500 hover:text-white p-2 hover:bg-zinc-800 rounded-xl transition-all">
                          {copiedLink ? <Check size={18} className="text-green-500" /> : <CopyIcon size={18} />}
                       </button>
                    </div>
                 </div>

                 <div className="bg-blue-500/5 p-4 rounded-2xl border border-blue-500/10 flex items-start gap-3">
                    <Users size={20} className="text-blue-500 mt-1 shrink-0" />
                    <p className="text-[11px] text-zinc-500 leading-relaxed font-medium">Team members can view and edit all project assets including generated scripts and thumbnails.</p>
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* Kanban Board */}
      <div className="flex-1 overflow-x-auto overflow-y-hidden custom-scrollbar">
         <div className="flex gap-6 h-full min-w-[1200px] pb-6">
            {columns.map(col => {
               const colProjects = projects.filter(p => p.status === col.id);
               return (
                  <div key={col.id} className="flex-1 flex flex-col min-w-[320px]">
                     <div className="flex items-center justify-between mb-6 px-4">
                        <div className="flex items-center gap-3">
                           <div className={`w-3 h-3 rounded-full ${col.color} shadow-lg shadow-current/20`}></div>
                           <h3 className="font-extrabold text-white text-sm uppercase tracking-widest">{col.label}</h3>
                           <span className="text-[10px] text-zinc-400 font-black px-2.5 py-1 bg-zinc-900 border border-zinc-800 rounded-full">{colProjects.length}</span>
                        </div>
                     </div>

                     <div className="flex-1 bg-zinc-900/20 border border-zinc-800/40 rounded-[2.5rem] p-4 space-y-4 overflow-y-auto custom-scrollbar shadow-inner">
                        {colProjects.map(project => (
                           <div key={project.id} className="bg-zinc-900 border border-zinc-800 hover:border-zinc-700 p-6 rounded-3xl shadow-sm hover:shadow-2xl transition-all group animate-scale-in hover-lift">
                              <div className="flex justify-between items-start mb-4">
                                 <span className="text-[9px] uppercase font-black text-zinc-600 tracking-[0.2em] bg-zinc-950 px-2.5 py-1 rounded-full border border-zinc-800 group-hover:text-white group-hover:border-zinc-700 transition-colors">{project.niche}</span>
                                 <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-all duration-300">
                                    <button onClick={() => setShareProject(project)} className="p-2 hover:bg-zinc-800 rounded-xl text-zinc-600 hover:text-blue-400 active-press transition-all">
                                       <Share2 size={16} />
                                    </button>
                                    <button onClick={() => handleDelete(project.id)} className="p-2 hover:bg-zinc-800 rounded-xl text-zinc-600 hover:text-red-400 active-press transition-all">
                                       <Trash2 size={16} />
                                    </button>
                                 </div>
                              </div>

                              <h4 className="font-extrabold text-white mb-4 leading-tight text-lg group-hover:text-red-500 transition-colors duration-300">{project.title}</h4>

                              {/* Assets Indicators */}
                              <div className="flex gap-2 mb-6">
                                 {[
                                   { has: project.assets.script, icon: FileText, label: 'Script', color: 'text-blue-400', bg: 'bg-blue-400/10' },
                                   { has: project.assets.thumbnail, icon: ImageIcon, label: 'Image', color: 'text-orange-400', bg: 'bg-orange-400/10' },
                                   { has: project.assets.seo, icon: Search, label: 'SEO', color: 'text-green-400', bg: 'bg-green-400/10' },
                                   { has: project.assets.video, icon: Video, label: 'Video', color: 'text-purple-400', bg: 'bg-purple-400/10' }
                                 ].map((asset, i) => (
