// --- Script ---
export const generateScriptStream = async (
  title: string, 
  tone: string, 
  scriptType: string = 'standard',
  instructions: string,
  onChunk: (text: string) => void,
  useFastModel: boolean = false
) => {
  const ai = getAiClient();

  let structureGuide = "";
  switch(scriptType) {
    case 'storytelling':
      structureGuide = `\n**Structure: Storytelling (Documentary Style)**
      1. **The Hook (0-60s)**: Start in the middle of the action or a high-stakes moment. Create immediate curiosity.
      2. **The Context (Inciting Incident)**: Why does this matter? What is the goal?
      3. **The Journey (Rising Action)**: The struggle, the research, the "trying and failing".
      4. **The Climax**: The realization or the peak moment of the video.
      5. **Resolution & Takeaway**: What did we learn? Emotional connection.`;
      break;
    case 'whitepaper':
      structureGuide = `\n**Structure: White Paper / Deep Dive Research**
      1. **Abstract / Executive Summary**: Brief overview of the findings.
      2. **Problem Statement**: The core issue being analyzed.
      3. **Methodology & Deep Analysis**: Data-driven, research-backed breakdown. Use "Chapter" markers.
      4. **Evidence & Counter-arguments**: Address nuances.
      5. **Conclusion & Future Outlook**: Final verdict.`;
      break;
    case 'tutorial':
      structureGuide = `\n**Structure: Step-by-Step Tutorial**
      1. **Result Showcase**: Show what they will build/achieve first.
      2. **Prerequisites**: What is needed.
      3. **The Steps**: Clear, numbered steps (Step 1, Step 2...).
      4. **Common Pitfalls**: What to avoid.
      5. **Final Polish**: The finished result.`;
      break;
    default: // standard
      structureGuide = `\n**Structure: Standard High-Retention YouTube**
      1. **The Hook (0-30s)**: Visual & Verbal hook.
      2. **Intro**: Brief context.
      3. **Content Body**: 3-5 Key Points / Listicles.
      4. **Call to Action**: Mid-roll or end.
      5. **Outro**: Link to next video.`;
      break;
  }

  let prompt = `Write a YouTube video script for a video titled: "${title}". 
  \nTone: ${tone}.
  \nScript Type: ${scriptType}.
  ${structureGuide}`;

  if (instructions) prompt += `\n\nSpecific Context & User Instructions:\n${instructions}`;
  prompt += `\n\nEnsure the pacing matches the requested type. Use Markdown formatting.`;

  const result = await ai.models.generateContentStream({
    model: useFastModel ? MODEL_NAMES.TEXT_LITE : MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.SCRIPT
    }
  });

  for await (const chunk of result) {
    if (chunk.text) onChunk(chunk.text);
  }
};

