  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);

  // Voiceover Modal State
  const [isVoiceoverModalOpen, setIsVoiceoverModalOpen] = useState(false);
  const [voiceoverText, setVoiceoverText] = useState('');
  const [selectedVoice, setSelectedVoice] = useState('Kore');
  const [isGeneratingVoice, setIsGeneratingVoice] = useState(false);
  const [previewAudioUrl, setPreviewAudioUrl] = useState<string | null>(null);

  const [isExporting, setIsExporting] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);

  // Refs for playback
  const previewVideoRef = useRef<HTMLVideoElement>(null);
  const previewAudioRef = useRef<HTMLAudioElement>(null);
  const editorFileInputRef = useRef<HTMLInputElement>(null);

  // --- GENERATOR LOGIC ---

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 4000);
    } else {
      setLoadingMsgIndex(0);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    setGeneratedVideoUrl(null);
    try {
      const url = await generateVideo(prompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
      }
    } catch (error: any) {
      console.error(error);
      alert("Video generation failed. Ensure you have selected a paid API key from the dialog.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const sendToEditor = () => {
    if (generatedVideoUrl) {
      addVideoToTimeline(generatedVideoUrl, `Veo Generation ${timeline.length + 1}`);
      setActiveTab('edit');
    }
  };

  // --- EDITOR LOGIC ---

  const addVideoToTimeline = (url: string, name: string) => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const duration = tempVid.duration || 10;
      const newClip: TimelineClip = {
        id: Date.now().toString(),
        type: 'video',
        url,
        name,
        duration,
        trimStart: 0,
        trimEnd: duration,
        timelineOffset: calculateNextOffset(),
        playbackSpeed: 1
      };
      const updatedTimeline = [...timeline, newClip];
      setTimeline(updatedTimeline);
      recalculateTotalDuration(updatedTimeline);
    };
  };

  const handleEditorUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const url = URL.createObjectURL(file);
      addVideoToTimeline(url, file.name);
    }
  };

  const calculateNextOffset = () => {
    if (timeline.length === 0) return 0;
    const last = timeline[timeline.length - 1];
    const clipDuration = (last.trimEnd - last.trimStart) / last.playbackSpeed;
    return last.timelineOffset + clipDuration;
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const clipDuration = (c.trimEnd - c.trimStart) / c.playbackSpeed;
      const end = c.timelineOffset + clipDuration;
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const handleGenerateVoiceoverPreview = async () => {
    if (!voiceoverText.trim()) return;
    setIsGeneratingVoice(true);
    setPreviewAudioUrl(null);
    try {
      const base64Audio = await generateSpeech(voiceoverText, selectedVoice);
      if (base64Audio) {
        const wavBlob = decodeRawPcmToWavBlob(base64Audio);
        const url = URL.createObjectURL(wavBlob);
        setPreviewAudioUrl(url);
      }
    } catch (e) {
      console.error(e);
      alert("Voiceover generation failed.");
    } finally {
      setIsGeneratingVoice(false);
    }
  };

  const addVoiceoverToTimeline = () => {
    if (!previewAudioUrl) return;

    const tempAudio = document.createElement('audio');
    tempAudio.src = previewAudioUrl;
    tempAudio.onloadedmetadata = () => {
       const duration = tempAudio.duration || 5; 
       const newClip: TimelineClip = {
          id: Date.now().toString(),
          type: 'audio',
          url: previewAudioUrl,
          name: `Voiceover: ${voiceoverText.substring(0, 15)}...`,
          duration,
          trimStart: 0,
          trimEnd: duration,
          timelineOffset: currentTime,
          playbackSpeed: 1
       };
       const newTimeline = [...timeline, newClip];
       setTimeline(newTimeline);
       recalculateTotalDuration(newTimeline);

       // Reset modal
       setVoiceoverText('');
       setPreviewAudioUrl(null);
       setIsVoiceoverModalOpen(false);
    };
  };

  const updateClip = (id: string, updates: Partial<TimelineClip>) => {
    const updated = timeline.map(c => c.id === id ? { ...c, ...updates } : c);
    setTimeline(updated);
    recalculateTotalDuration(updated);
  };

  const removeClip = (id: string) => {
    const updated = timeline.filter(c => c.id !== id);
    setTimeline(updated);
    recalculateTotalDuration(updated);
  };

  const handleSmartTrim = async (clipId: string) => {
    const clip = timeline.find(c => c.id === clipId);
    if (!clip) return;
    const thinking = confirm(`Allow AI to suggest optimal trimming for "${clip.name}"?`);
    if (!thinking) return;

    const suggestedStart = clip.duration * 0.1;
    const suggestedEnd = clip.duration * 0.9;
    updateClip(clipId, { trimStart: suggestedStart, trimEnd: suggestedEnd });
  };

  const handleExport = () => {
    if (timeline.length === 0) return;
    setIsExporting(true);
    setExportProgress(0);
    const interval = setInterval(() => {
      setExportProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => {
             setIsExporting(false);
             alert("Project exported successfully!");
          }, 500);
          return 100;
        }
        return prev + 5;
      });
    }, 200);
  };

  // --- PLAYBACK ENGINE ---

  const togglePlay = () => {
    setIsPlaying(!isPlaying);
  };

  const seek = (time: number) => {
    setCurrentTime(Math.max(0, Math.min(time, totalDuration)));
  };

  const syncPlayer = (time: number) => {
    const videoClip = timeline.find(c => {
      const clipEffectiveDuration = (c.trimEnd - c.trimStart) / c.playbackSpeed;
      return c.type === 'video' && time >= c.timelineOffset && time < (c.timelineOffset + clipEffectiveDuration);
    });

    if (previewVideoRef.current) {
       if (videoClip) {
          if (!previewVideoRef.current.src.includes(videoClip.url)) {
             previewVideoRef.current.src = videoClip.url;
          }
          const timeIntoClip = time - videoClip.timelineOffset;
          const internalTime = videoClip.trimStart + (timeIntoClip * videoClip.playbackSpeed);
          if (previewVideoRef.current.playbackRate !== videoClip.playbackSpeed) {
            previewVideoRef.current.playbackRate = videoClip.playbackSpeed;
          }
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.3) {
            previewVideoRef.current.currentTime = internalTime;
          }
          if (isPlaying) previewVideoRef.current.play().catch(() => {});
          else previewVideoRef.current.pause();
          previewVideoRef.current.style.opacity = '1';
       } else {
          previewVideoRef.current.pause();
          previewVideoRef.current.style.opacity = '0';
       }
    }

    const audioClip = timeline.find(c => {
        const clipEffectiveDuration = (c.trimEnd - c.trimStart) / c.playbackSpeed;
        return c.type === 'audio' && time >= c.timelineOffset && time < (c.timelineOffset + clipEffectiveDuration);
    });

    if (previewAudioRef.current) {
        if (audioClip) {
           if (!previewAudioRef.current.src.includes(audioClip.url)) {
              previewAudioRef.current.src = audioClip.url;
           }
           const timeIntoClip = time - audioClip.timelineOffset;
           const internalTime = audioClip.trimStart + (timeIntoClip * audioClip.playbackSpeed);
           if (previewAudioRef.current.playbackRate !== audioClip.playbackSpeed) {
              previewAudioRef.current.playbackRate = audioClip.playbackSpeed;
           }
           if (Math.abs(previewAudioRef.current.currentTime - internalTime) > 0.3) {
             previewAudioRef.current.currentTime = internalTime;
           }
           if (isPlaying) previewAudioRef.current.play().catch(() => {});
           else previewAudioRef.current.pause();
        } else {
           previewAudioRef.current.pause();
        }
    }
  };

  useEffect(() => {
    let animationFrameId: number;
    const animate = () => {
      if (isPlaying) {
        setCurrentTime(prev => {
          const next = prev + 0.033;
          if (next >= totalDuration && totalDuration > 0) {
            setIsPlaying(false);
            return 0;
          }
          return next;
        });
      }
      animationFrameId = requestAnimationFrame(animate);
    };
    animationFrameId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  useEffect(() => {
    syncPlayer(currentTime);
  }, [currentTime, timeline, isPlaying]);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4">
       <header className="flex items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6">
