  { id: '3D Render', label: '3D CGI', desc: 'Pixar-style depth' },
  { id: 'Anime / Manga', label: 'Anime', desc: 'Vibrant cell-shading' },
  { id: 'Comic Book', label: 'Comic', desc: 'Stark lines & halftones' },
  { id: 'Cyberpunk', label: 'Cyberpunk', desc: 'Neon & high tech' },
  { id: 'Minimalist', label: 'Minimal', desc: 'Clean & flat design' },
  { id: 'Oil Painting', label: 'Classic', desc: 'Traditional texture' },
  { id: 'Pixel Art', label: 'Retro', desc: '8-bit nostalgia' }
