    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const enhanced = await enhanceThumbnailPrompt(prompt);
      setPrompt(enhanced);
    } catch (e) {
      console.error(e);
    } finally {
      setEnhancing(false);
    }
