                   </button>
                 )}
               </div>
               <textarea
                 value={prompt}
                 onChange={(e) => setPrompt(e.target.value)}
                 placeholder={mode === 'generate' ? "Describe your thumbnail vision in detail..." : "What would you like to change? (e.g. 'Add a cyberpunk visor to the face')"}
                 className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 focus:ring-2 focus:ring-orange-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed shadow-inner"
               />
             </div>

             {/* Art Styles Selection */}
             {mode === 'generate' && (
               <div className="space-y-4">
                 <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Artistic Identity</label>
                 <div className="grid grid-cols-2 gap-3 max-h-48 overflow-y-auto p-1 custom-scrollbar">
                    {STYLES.map(s => (
                      <button 
                        key={s.id}
                        type="button"
                        onClick={() => setStyle(s.id)}
                        className={`p-4 rounded-2xl border text-left transition-all group ${style === s.id ? 'bg-orange-500/10 border-orange-500/50 text-white shadow-xl' : 'bg-zinc-950 border-zinc-800 hover:border-zinc-700 text-zinc-500'}`}
                      >
                         <span className="block font-black text-[11px] group-hover:text-white transition-colors">{s.label}</span>
                         <span className="block text-[9px] opacity-60 font-medium group-hover:opacity-100 transition-opacity">{s.desc}</span>
                      </button>
                    ))}
                 </div>
               </div>
             )}

             {/* Formats & Quality */}
             <div className="grid grid-cols-2 gap-6 pt-2">
                <div className="space-y-3">
                   <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Format</label>
                   <div className="flex gap-2">
                      {ASPECT_RATIOS.map(ar => (
                        <button 
                           key={ar.id}
                           type="button"
                           onClick={() => setAspectRatio(ar.id)}
                           title={ar.label}
                           className={`p-3 rounded-xl border transition-all ${aspectRatio === ar.id ? 'bg-white text-black border-white shadow-lg' : 'bg-zinc-950 border-zinc-800 text-zinc-600 hover:bg-zinc-800 hover:text-white'}`}
                        >
                           {ar.icon}
