                      ))}
                   </div>
                </div>

                {genMode === 'pro' && (
                  <div className="space-y-3">
                    <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Output Tier</label>
                    <select 
                       value={imageSize}
                       onChange={(e) => setImageSize(e.target.value)}
