                    >
                       {SIZES.map(s => <option key={s} value={s}>{s} Resolution</option>)}
                    </select>
                  </div>
                )}
             </div>

             <button
              type="submit"
              disabled={loading || (!prompt && mode === 'generate')}
              className={`w-full py-5 rounded-3xl font-black uppercase text-xs tracking-[0.2em] transition-all shadow-xl flex items-center justify-center gap-3 active-press ${loading ? 'bg-zinc-800 text-zinc-600' : 'bg-orange-600 hover:bg-orange-500 text-white shadow-orange-600/20'}`}
            >
              {loading ? <Loader2 className="animate-spin" /> : mode === 'generate' ? <><Zap size={18} fill="currentColor" /> Manifest Visual</> : <><Wand2 size={18} /> Apply Edit</>}
            </button>
          </form>

          <div className="p-6 bg-zinc-900/50 border border-zinc-800 rounded-[2rem] flex items-start gap-4">
             <div className="p-3 bg-blue-500/10 rounded-2xl text-blue-400 shadow-lg shadow-blue-500/5">
                <Info size={20} />
             </div>
             <div>
                <h4 className="text-[10px] font-bold text-white uppercase tracking-widest mb-1">Director's Note</h4>
                <p className="text-[11px] text-zinc-500 leading-relaxed font-medium">
                  "Imagen 4.0 provides the best composition for complex scenes, while Flash is perfect for testing rough layouts."
