import React, { useState, useRef } from 'react';
import { generateSpeech, transcribeAudio } from '../services/gemini';
import { Loader2, Mic, Volume2, FileAudio, PlayCircle, Upload, FileText, X, Music } from 'lucide-react';

export const AudioStudio: React.FC = () => {
  const [tab, setTab] = useState<'tts' | 'stt'>('tts');
  const [text, setText] = useState('');
  const [audioResult, setAudioResult] = useState<string | null>(null);
  const [transcription, setTranscription] = useState('');
  const [loading, setLoading] = useState(false);
  const [isRecording, setIsRecording] = useState(false);

  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // TTS Handler
  const handleTTS = async () => {
    if (!text) return;
    setLoading(true);
    try {
      const base64 = await generateSpeech(text);
      if (base64) {
        playRawAudio(base64);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const playRawAudio = async (base64: string) => {
    try {
      const binaryString = atob(base64);
      const len = binaryString.length;
      const bytes = new Uint8Array(len);
      for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);

      const audioContext = new (window.AudioContext || window.webkitAudioContext)({sampleRate: 24000});
      const buffer = audioContext.createBuffer(1, bytes.length / 2, 24000);
      const channelData = buffer.getChannelData(0);
      const dataInt16 = new Int16Array(bytes.buffer);

      for (let i = 0; i < dataInt16.length; i++) {
        channelData[i] = dataInt16[i] / 32768.0;
      }

      const source = audioContext.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContext.destination);
      source.start();
      setAudioResult("playing"); 
      setTimeout(() => setAudioResult(null), buffer.duration * 1000);

    } catch (e) {
      console.error("Audio decode error", e);
    }
  };

  // STT Handlers
  const startRecording = async () => {
    setTranscription('');
    setUploadedFile(null);
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const mediaRecorder = new MediaRecorder(stream);
    mediaRecorderRef.current = mediaRecorder;
    audioChunksRef.current = [];

    mediaRecorder.ondataavailable = (event) => {
      audioChunksRef.current.push(event.data);
    };

    mediaRecorder.onstop = async () => {
      const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
      setLoading(true);
      try {
        const text = await transcribeAudio(audioBlob);
        setTranscription(text);
      } catch (e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };

    mediaRecorder.start();
    setIsRecording(true);
  };

  const stopRecording = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setUploadedFile(file);
      setTranscription('');
    }
  };

  const handleTranscribeFile = async () => {
    if (!uploadedFile) return;
    setLoading(true);
    try {
      const text = await transcribeAudio(uploadedFile);
      setTranscription(text);
    } catch (e) {
      console.error(e);
      alert("Failed to transcribe file.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-fade-in pb-10">
      <div className="text-center space-y-4 py-4">
        <h2 className="text-4xl font-extrabold text-white tracking-tight">Audio Studio</h2>
        <p className="text-zinc-400 text-lg">Generate realistic narration or convert your speech to text with pinpoint accuracy.</p>

        <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800 w-fit mx-auto mt-6">
          <button 
            onClick={() => { setTab('tts'); setTranscription(''); }}
            className={`px-8 py-2.5 rounded-xl font-bold text-sm transition-all ${tab === 'tts' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
          >
            Narrator (TTS)
          </button>
          <button 
            onClick={() => { setTab('stt'); setAudioResult(null); }}
            className={`px-8 py-2.5 rounded-xl font-bold text-sm transition-all ${tab === 'stt' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
          >
            Transcribe (STT)
          </button>
        </div>
      </div>

      <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 md:p-12 shadow-2xl relative overflow-hidden">
        {tab === 'tts' ? (
          <div className="space-y-6 animate-fade-in">
             <div className="flex items-center gap-3 mb-2">
                <div className="p-3 bg-purple-500/10 rounded-2xl text-purple-400">
                   <Volume2 size={24} />
                </div>
                <h3 className="text-xl font-bold text-white">Voice Synthesis Engine</h3>
             </div>
             <textarea
               value={text}
               onChange={(e) => setText(e.target.value)}
               placeholder="Enter the script for your video narration..."
               className="w-full h-48 bg-zinc-950 border border-zinc-800 rounded-3xl p-6 focus:ring-2 focus:ring-purple-500/50 outline-none text-white resize-none text-lg leading-relaxed shadow-inner transition-all"
             />
             <button
               onClick={handleTTS}
               disabled={loading || !text}
               className="w-full bg-purple-600 hover:bg-purple-500 disabled:opacity-50 text-white py-5 rounded-3xl font-black uppercase text-xs tracking-widest transition-all shadow-xl shadow-purple-600/20 flex items-center justify-center gap-3 active-press"
             >
               {loading || audioResult === 'playing' ? <Loader2 className="animate-spin" size={20} /> : <PlayCircle size={20} />}
               {audioResult === 'playing' ? 'Synthesizing & Playing...' : 'Generate Voiceover'}
             </button>
          </div>
        ) : (
          <div className="space-y-10 animate-fade-in">
             <div className="flex flex-col md:flex-row gap-8">
                {/* Method 1: Record */}
                <div className="flex-1 flex flex-col items-center justify-center p-8 bg-zinc-950 border border-zinc-800 rounded-[2rem] group hover:border-red-500/30 transition-all">
                   <h4 className="text-xs font-black text-zinc-500 uppercase tracking-widest mb-6">Live Recording</h4>
                   <button
                     onMouseDown={startRecording}
                     onMouseUp={stopRecording}
                     onTouchStart={startRecording}
                     onTouchEnd={stopRecording}
                     className={`w-32 h-32 rounded-full flex items-center justify-center transition-all active-press ${isRecording ? 'bg-red-500 scale-110 shadow-[0_0_40px_rgba(239,68,68,0.4)] animate-pulse' : 'bg-zinc-900 border border-zinc-800 hover:border-red-500/50'}`}
                   >
                     <Mic size={48} className={isRecording ? 'text-white' : 'text-zinc-600 group-hover:text-red-500 transition-colors'} />
                   </button>
                   <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-tighter mt-6">
                      {isRecording ? 'Capturing Audio...' : 'Hold to record'}
                   </p>
                </div>

                <div className="hidden md:flex items-center text-zinc-800 font-black uppercase text-xs">OR</div>

                {/* Method 2: Upload */}
                <div className="flex-1 flex flex-col items-center justify-center p-8 bg-zinc-950 border border-zinc-800 rounded-[2rem] group hover:border-blue-500/30 transition-all">
                   <h4 className="text-xs font-black text-zinc-500 uppercase tracking-widest mb-6">File Upload</h4>

                   {uploadedFile ? (
                      <div className="w-full flex flex-col items-center animate-scale-in">
                         <div className="w-32 h-32 rounded-[2rem] bg-blue-600/10 border border-blue-500/30 flex items-center justify-center text-blue-500 mb-4 relative">
                            <Music size={40} />
                            <button 
                              onClick={() => setUploadedFile(null)} 
                              className="absolute -top-2 -right-2 bg-zinc-800 hover:bg-zinc-700 p-1.5 rounded-full border border-zinc-700 transition-colors"
                            >
                               <X size={14} className="text-zinc-400" />
                            </button>
                         </div>
                         <p className="text-white text-xs font-bold truncate max-w-[150px] mb-4">{uploadedFile.name}</p>
                         <button 
                           onClick={handleTranscribeFile}
                           disabled={loading}
                           className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-600/20 active-press transition-all"
                         >
                            {loading ? <Loader2 className="animate-spin" size={14} /> : 'Process File'}
                         </button>
                      </div>
                   ) : (
                      <>
                        <button
                          onClick={() => fileInputRef.current?.click()}
                          className="w-32 h-32 rounded-full bg-zinc-900 border border-zinc-800 flex items-center justify-center hover:border-blue-500/50 transition-all active-press"
                        >
