const ShortsScriptRenderer = ({ script }: { script: string }) => {
  // Regex to find bracketed text [Visual: ...] and wrap in styled spans
  const parts = script.split(/(\[.*?\])/g);

  const wordCount = script.split(/\s+/).filter(w => !w.startsWith('[') && w.length > 0).length;
  const estSeconds = Math.round((wordCount / 140) * 60);

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between bg-zinc-900 border border-zinc-800 p-4 rounded-2xl shadow-inner">
        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2 text-zinc-400">
              <Clock size={14} className="text-zinc-500" />
              <span className="text-xs font-bold uppercase tracking-widest">Est. Duration:</span>
              <span className={`text-xs font-black ${estSeconds > 60 ? 'text-red-500' : 'text-green-500'}`}>
                {estSeconds}s {estSeconds > 60 && '(OVER LIMIT)'}
              </span>
           </div>
           <div className="w-px h-4 bg-zinc-800"></div>
           <div className="flex items-center gap-2 text-zinc-400">
              <FileText size={14} className="text-zinc-500" />
              <span className="text-xs font-bold uppercase tracking-widest">Word Count:</span>
              <span className="text-xs font-black text-white">{wordCount}</span>
           </div>
        </div>
        <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${estSeconds <= 60 ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-500/10 text-red-500 border-red-500/20'}`}>
          {estSeconds <= 60 ? 'Mobile Optimized' : 'Needs Trimming'}
        </div>
      </div>

      <div className="bg-zinc-950 border border-zinc-800 rounded-3xl p-8 shadow-2xl relative group overflow-hidden">
        <div className="absolute top-0 left-0 w-1 h-full bg-red-600"></div>
        <div className="max-h-[500px] overflow-y-auto pr-4 custom-scrollbar">
           <p className="text-white text-xl md:text-2xl font-bold leading-[1.8] tracking-tight">
             {parts.map((part, i) => (
               part.startsWith('[') && part.endsWith(']') ? (
                 <span key={i} className="block my-4 bg-red-600/10 text-red-500 border border-red-600/20 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-[0.2em] w-fit">
                    <Sparkles size={12} className="inline mr-2 -mt-1" />
                    {part.slice(1, -1)}
                 </span>
               ) : (
                 <span key={i}>{part}</span>
               )
             ))}
           </p>
        </div>
      </div>
    </div>
  );
};

export const RepurposeEngine: React.FC = () => {
  const [sourceText, setSourceText] = useState('');
  const [result, setResult] = useState<RepurposedContent | null>(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'thread' | 'blog' | 'newsletter' | 'shorts'>('thread');

  const handleGenerate = async () => {
    if (!sourceText.trim()) return;
    setLoading(true);
    try {
      const content = await generateRepurposedContent(sourceText);
      setResult(content);
    } catch (e) {
      console.error(e);
      alert("Repurposing failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copied to clipboard!");
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col md:flex-row gap-6 animate-fade-in">
       {/* Input Side */}
       <div className="w-full md:w-1/3 flex flex-col gap-4">
          <div className="space-y-2 shrink-0">
             <h2 className="text-2xl font-bold text-white">Content Repurposer</h2>
             <p className="text-zinc-400 text-sm">Turn one script into 4 pieces of content instantly.</p>
          </div>

          <div className="flex-1 flex flex-col bg-zinc-900 border border-zinc-800 rounded-2xl p-4">
             <textarea 
               value={sourceText} 
               onChange={e => setSourceText(e.target.value)}
               className="flex-1 bg-zinc-950 border border-zinc-800 rounded-xl p-4 text-white text-sm resize-none focus:ring-2 focus:ring-blue-500/50 outline-none"
               placeholder="Paste your video script, transcript, or rough notes here..."
             />
             <button 
               onClick={handleGenerate}
               disabled={loading || !sourceText}
               className="mt-4 w-full bg-blue-600 hover:bg-blue-500 disabled:opacity-50 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-600/20 flex items-center justify-center gap-2"
             >
                {loading ? <Loader2 className="animate-spin" /> : <><RefreshCcw size={18} /> Repurpose Content</>}
             </button>
          </div>
       </div>

       {/* Output Side */}
