// --- Video (Veo) ---
export const generateVideo = async (
  prompt: string, 
  aspectRatio: '16:9' | '9:16', 
  imageBytes?: string,
  resolution: '720p' | '1080p' = '1080p'
): Promise<string | null> => {
  // Use explicit API key selection check as required for Veo
  if (window.aistudio) {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
       await window.aistudio.openSelectKey();
       // Guidelines: assume key selection was successful after triggering openSelectKey and proceed
    }
  }

  try {
    // Guidelines: Create a new GoogleGenAI instance right before making an API call 
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let operation;

    const config: any = {
      numberOfVideos: 1,
      resolution: resolution,
      aspectRatio: aspectRatio
    };

    if (imageBytes) {
      const cleanBase64 = imageBytes.replace(/^data:image\/\w+;base64,/, "");
      const mimeMatch = imageBytes.match(/^data:(image\/\w+);base64,/);
      const mimeType = mimeMatch ? mimeMatch[1] : 'image/png';

      operation = await ai.models.generateVideos({
        model: MODEL_NAMES.VIDEO_FAST,
        prompt: prompt || "Animate this image in a cinematic way.",
        image: {
          imageBytes: cleanBase64,
          mimeType: mimeType
        },
        config
      });
    } else {
      operation = await ai.models.generateVideos({
        model: MODEL_NAMES.VIDEO_FAST,
        prompt: prompt,
        config
      });
    }

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({operation: operation});
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) return null;

    // Guidelines: You must append an API key when fetching from the download link.
    const res = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!res.ok) {
       const errText = await res.text();
       if (errText.includes("Requested entity was not found")) {
          if (window.aistudio) await window.aistudio.openSelectKey();
       }
       throw new Error("Failed to download video bytes");
    }
    const blob = await res.blob();
    return URL.createObjectURL(blob);

  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      if (window.aistudio) await window.aistudio.openSelectKey();
    }
    throw error;
  }
};

// --- Audio (TTS & STT) ---
export const generateSpeech = async (text: string, voiceName: string = 'Kore'): Promise<string | null> => {
  const ai = getAiClient();
  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TTS,
    contents: [{ parts: [{ text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  return base64Audio || null;
};

export const transcribeAudio = async (audioBlob: Blob): Promise<string> => {
  const ai = getAiClient();
  const reader = new FileReader();
  const base64Promise = new Promise<string>((resolve) => {
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(audioBlob);
  });
  const base64Data = await base64Promise;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_FAST,
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: audioBlob.type,
            data: base64Data
          }
        },
        { text: "Transcribe this audio exactly." }
      ]
    }
  });

  return response.text || "";
};

// --- Research / Chat ---
export const researchChat = async (
  history: any[], 
  message: string, 
  image?: string,
  useThinking: boolean = false,
  tools: { search: boolean; maps: boolean } = { search: false, maps: false }
) => {
  const ai = getAiClient();

  const configuredTools: any[] = [];
  if (tools.search) configuredTools.push({ googleSearch: {} });
  if (tools.maps) configuredTools.push({ googleMaps: {} });

  const config: any = {
    systemInstruction: SYSTEM_INSTRUCTIONS.RESEARCH,
    tools: configuredTools.length > 0 ? configuredTools : undefined
  };

  if (useThinking) {
    config.thinkingConfig = { thinkingBudget: 32768 };
  }

  const model = MODEL_NAMES.TEXT_SMART; 

  const parts: any[] = [];
  if (image) {
    const cleanBase64 = image.replace(/^data:image\/\w+;base64,/, "");
    parts.push({
      inlineData: {
        data: cleanBase64,
        mimeType: 'image/png' 
      }
    });
  }
  parts.push({ text: message });

  const response = await ai.models.generateContent({
    model: model,
    contents: { parts },
    config: config
  });

  const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => {
    if (chunk.web) return { title: chunk.web.title, uri: chunk.web.uri };
    if (chunk.maps) return { title: chunk.maps.title || "Maps Location", uri: chunk.maps.uri || "" }; 
    return null;
  }).filter(Boolean) || [];

  return {
    text: response.text || "No response generated.",
    sources
  };
};

