                 <h3 className="text-xs font-black uppercase tracking-widest text-zinc-400">Master Sequence</h3>
                 <div className="flex items-center gap-4">
                    <button 
                      onClick={() => editorFileInputRef.current?.click()}
                      className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-white px-5 py-2.5 rounded-xl border border-zinc-700 transition-all active-press"
