import React, { useState, useRef, useEffect } from 'react';
import { researchChat } from '../services/gemini';
import { ChatMessage, ResearchSession } from '../types';
import { 
  Loader2, 
  Send, 
  MapPin, 
  Search, 
  BrainCircuit, 
  Image as ImageIcon, 
  Link as LinkIcon, 
  History, 
  Plus, 
  Trash2, 
  MessageSquare,
  Clock,
  ChevronLeft,
  ChevronRight,
  PanelLeftClose,
  PanelLeftOpen
} from 'lucide-react';

export const ResearchAssistant: React.FC = () => {
  const [sessions, setSessions] = useState<ResearchSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  // Tools Config
  const [useSearch, setUseSearch] = useState(true);
  const [useMaps, setUseMaps] = useState(false);
  const [useThinking, setUseThinking] = useState(false);
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const endRef = useRef<HTMLDivElement>(null);

  // Load from local storage
  useEffect(() => {
    const saved = localStorage.getItem('ranktica_research_v2');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setActiveSessionId(parsed[0].id);
      } catch (e) { console.error("History load error", e); }
    }
  }, []);

  // Save to local storage
  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('ranktica_research_v2', JSON.stringify(sessions));
    }
  }, [sessions]);

  // Scroll to bottom on new messages
  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [sessions, activeSessionId]);

  const activeSession = sessions.find(s => s.id === activeSessionId) || null;

  const createNewSession = () => {
    const newSession: ResearchSession = {
      id: Date.now().toString(),
      title: 'New Research Chat',
      messages: [],
      lastUpdated: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
  };

  const deleteSession = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const updated = sessions.filter(s => s.id !== id);
    setSessions(updated);
    if (activeSessionId === id) {
      setActiveSessionId(updated.length > 0 ? updated[0].id : null);
    }
  };

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() && !uploadedImage) return;

    let currentId = activeSessionId;
    let currentSessions = [...sessions];

    // Create session if none active
    if (!currentId) {
      const newSession: ResearchSession = {
        id: Date.now().toString(),
        title: input.trim().substring(0, 40) || 'Image Analysis',
        messages: [],
        lastUpdated: Date.now()
      };
      currentSessions = [newSession, ...currentSessions];
      currentId = newSession.id;
      setSessions(currentSessions);
      setActiveSessionId(currentId);
    }

    const userMsg: ChatMessage = { role: 'user', text: input, image: uploadedImage || undefined };

    // Update local state with user message
    const updatedSessions = currentSessions.map(s => {
      if (s.id === currentId) {
        return {
          ...s,
          messages: [...s.messages, userMsg],
          lastUpdated: Date.now(),
          // Auto-title based on first message
          title: s.messages.length === 0 ? userMsg.text.substring(0, 40) : s.title
        };
      }
      return s;
    });

    setSessions(updatedSessions);
    setInput('');
    setUploadedImage(null);
    setLoading(true);

    try {
      const sessionMessages = updatedSessions.find(s => s.id === currentId)?.messages || [];
      const response = await researchChat(
        sessionMessages, 
        userMsg.text,
        userMsg.image,
        useThinking,
        { search: useSearch, maps: useMaps }
      );

      const modelMsg: ChatMessage = {
        role: 'model',
        text: response.text,
        sources: response.sources
      };

      setSessions(prev => prev.map(s => {
        if (s.id === currentId) {
          return { ...s, messages: [...s.messages, modelMsg], lastUpdated: Date.now() };
        }
        return s;
      }));

    } catch (err) {
      console.error(err);
      setSessions(prev => prev.map(s => {
        if (s.id === currentId) {
          return { ...s, messages: [...s.messages, { role: 'model', text: "Error connecting to research assistant." }] };
        }
        return s;
      }));
    } finally {
      setLoading(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="max-w-7xl mx-auto h-[calc(100vh-6rem)] flex gap-6 animate-fade-in relative">

      {/* Sidebar - History */}
      <aside className={`flex flex-col bg-zinc-900 border border-zinc-800 rounded-[2.5rem] transition-all duration-500 overflow-hidden shadow-2xl ${sidebarOpen ? 'w-80' : 'w-0 opacity-0 -ml-6'}`}>
         <div className="p-6 border-b border-zinc-800 flex items-center justify-between shrink-0">
            <h3 className="text-sm font-black uppercase tracking-[0.2em] text-zinc-500 flex items-center gap-2">
               <History size={16} /> Research Logs
            </h3>
            <button 
              onClick={createNewSession}
              className="p-2 bg-red-600 hover:bg-red-500 text-white rounded-xl shadow-lg shadow-red-600/20 active-press transition-all"
              title="New Research"
            >
              <Plus size={18} />
            </button>
         </div>

         <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
            {sessions.length === 0 ? (
               <div className="h-full flex flex-col items-center justify-center text-zinc-700 text-center px-6">
                  <MessageSquare size={32} className="mb-4 opacity-20" />
                  <p className="text-xs font-bold uppercase tracking-widest leading-loose">No research records found in archive</p>
               </div>
            ) : (
               sessions.map(s => (
                  <button
                    key={s.id}
                    onClick={() => setActiveSessionId(s.id)}
                    className={`w-full text-left p-4 rounded-2xl border transition-all group relative overflow-hidden ${activeSessionId === s.id ? 'bg-zinc-800 border-zinc-700 shadow-xl' : 'bg-zinc-950/50 border-zinc-900 hover:border-zinc-800'}`}
                  >
                     <div className="flex justify-between items-start mb-2">
                        <span className="text-[9px] font-black uppercase tracking-widest text-zinc-500">
                           {new Date(s.lastUpdated).toLocaleDateString()}
                        </span>
                        <Trash2 
                          size={14} 
                          className="text-zinc-700 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all" 
                          onClick={(e) => deleteSession(e, s.id)}
                        />
                     </div>
                     <p className={`text-sm font-bold truncate ${activeSessionId === s.id ? 'text-white' : 'text-zinc-400 group-hover:text-zinc-200'}`}>
                        {s.title || 'Untitled Research'}
                     </p>
                     <div className="flex items-center gap-2 mt-2">
                        <div className="w-1 h-1 rounded-full bg-red-500 animate-pulse"></div>
                        <span className="text-[10px] text-zinc-600 font-medium uppercase">{s.messages.length} exchanges</span>
                     </div>
                     {activeSessionId === s.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-red-600"></div>}
                  </button>
               ))
            )}
         </div>
      </aside>

      {/* Main Chat Stage */}
      <div className="flex-1 flex flex-col min-w-0 bg-zinc-950 border border-zinc-900 rounded-[3rem] overflow-hidden shadow-inner relative">

        {/* Toggle Sidebar Button */}
        <button 
          onClick={() => setSidebarOpen(!sidebarOpen)}
          className="absolute left-6 top-6 z-20 p-2 text-zinc-500 hover:text-white bg-zinc-900/50 hover:bg-zinc-800 border border-zinc-800 rounded-xl transition-all active-press"
        >
          {sidebarOpen ? <PanelLeftClose size={18} /> : <PanelLeftOpen size={18} />}
        </button>

        <header className="p-6 pt-7 border-b border-zinc-900/50 flex flex-col md:flex-row md:items-center justify-between shrink-0 gap-4">
          <div className="pl-12 md:pl-14">
             <h2 className="text-xl font-black text-white tracking-tight flex items-center gap-3">
               <BrainCircuit size={24} className="text-red-600" />
               {activeSession?.title || 'Creative Intelligence'}
             </h2>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-zinc-600 mt-1">Multi-Modal Research Suite</p>
          </div>

          <div className="flex gap-2 self-end">
             <button 
               onClick={() => setUseThinking(!useThinking)}
               className={`p-2.5 rounded-xl border transition-all active-press ${useThinking ? 'bg-purple-900/20 border-purple-500 text-purple-400 shadow-lg shadow-purple-500/10' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}
               title="Reasoning Engine"
             >
               <BrainCircuit size={16} />
             </button>
             <button 
               onClick={() => setUseSearch(!useSearch)}
               className={`p-2.5 rounded-xl border transition-all active-press ${useSearch ? 'bg-blue-900/20 border-blue-500 text-blue-400 shadow-lg shadow-blue-500/10' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}
               title="Google Grounding"
             >
               <Search size={16} />
             </button>
             <button 
               onClick={() => setUseMaps(!useMaps)}
               className={`p-2.5 rounded-xl border transition-all active-press ${useMaps ? 'bg-green-900/20 border-green-500 text-green-400 shadow-lg shadow-green-500/10' : 'bg-zinc-900 border-zinc-800 text-zinc-600'}`}
               title="Maps Localization"
             >
               <MapPin size={16} />
             </button>
          </div>
        </header>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto px-6 py-8 space-y-8 custom-scrollbar">
           {(!activeSession || activeSession.messages.length === 0) && (
             <div className="h-full flex flex-col items-center justify-center text-center max-w-sm mx-auto space-y-6">
               <div className="relative">
                  <div className="w-24 h-24 rounded-[2rem] bg-zinc-900 border border-zinc-800 flex items-center justify-center animate-pulse">
                     <BrainCircuit size={40} className="text-zinc-700" />
                  </div>
                  <div className="absolute inset-0 bg-red-600 blur-3xl opacity-5"></div>
               </div>
               <div>
                  <p className="text-white font-bold text-lg mb-2">Architect your Strategy</p>
                  <p className="text-xs text-zinc-500 leading-relaxed font-medium uppercase tracking-widest">
                    Ask for competitor analysis, niche trends, or upload a thumbnail draft for a deep critique.
                  </p>
               </div>
             </div>
           )}

           {activeSession?.messages.map((msg, idx) => (
             <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in`}>
                <div className={`max-w-[85%] md:max-w-[75%] rounded-[2rem] p-6 shadow-xl ${msg.role === 'user' ? 'bg-red-600 text-white shadow-red-600/10' : 'bg-zinc-900 border border-zinc-800 text-zinc-300'}`}>
                   {msg.image && (
                     <div className="mb-4 rounded-2xl overflow-hidden border border-white/10 shadow-2xl">
                        <img src={msg.image} alt="User upload" className="max-w-full h-auto" />
                     </div>
                   )}
                   <div className="whitespace-pre-wrap leading-relaxed text-[15px] font-medium">{msg.text}</div>

                   {msg.sources && msg.sources.length > 0 && (
                     <div className="mt-6 pt-4 border-t border-zinc-800">
                       <p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-3 flex items-center gap-2">
                          <LinkIcon size={12} /> External Intelligence
                       </p>
                       <div className="flex flex-wrap gap-2">
                         {msg.sources.map((s, i) => (
                           <a key={i} href={s.uri} target="_blank" rel="noreferrer" className="flex items-center gap-2 text-xs bg-zinc-950 border border-zinc-800 px-3 py-1.5 rounded-xl hover:border-blue-500/50 hover:text-blue-400 transition-all">
                              {s.title}
                           </a>
                         ))}
                       </div>
                     </div>
                   )}
                </div>
             </div>
           ))}
           {loading && (
             <div className="flex justify-start animate-fade-in">
               <div className="bg-zinc-900 border border-zinc-800 rounded-3xl p-6 shadow-xl">
                  <div className="flex gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-red-600 animate-bounce"></div>
                    <div className="w-1.5 h-1.5 rounded-full bg-red-600 animate-bounce delay-75"></div>
                    <div className="w-1.5 h-1.5 rounded-full bg-red-600 animate-bounce delay-150"></div>
                  </div>
               </div>
             </div>
           )}
           <div ref={endRef} />
        </div>

        {/* Input Area */}
        <div className="p-6 shrink-0 bg-zinc-950">
           <form onSubmit={handleSend} className="max-w-4xl mx-auto bg-zinc-900/50 p-2 rounded-[2rem] border border-zinc-800 flex items-end gap-2 relative shadow-2xl">
            {uploadedImage && (
              <div className="absolute bottom-full left-6 mb-4 p-2 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-2xl animate-scale-in">
                 <img src={uploadedImage} className="h-24 w-auto rounded-xl object-cover" />
                 <button type="button" onClick={() => setUploadedImage(null)} className="absolute -top-3 -right-3 bg-red-600 text-white rounded-full p-1.5 shadow-xl hover:bg-red-500 transition-colors">
                    <Trash2 size={12} />
                 </button>
              </div>
            )}

            <button 
              type="button" 
              onClick={() => fileInputRef.current?.click()}
              className="p-4 text-zinc-500 hover:text-white transition-colors active-press"
              title="Add Context Image"
            >
              <ImageIcon size={22} />
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleImageUpload} />

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask for strategy, analysis, or trends..."
              className="flex-1 bg-transparent border-none outline-none text-white p-4 resize-none max-h-48 text-[15px] leading-relaxed font-medium placeholder:text-zinc-600"
              rows={1}
