// --- Video (Veo) ---
export const generateVideo = async (
  prompt: string, 
  aspectRatio: '16:9' | '9:16', 
  imageBytes?: string,
  resolution: '720p' | '1080p' = '1080p'
): Promise<string | null> => {
  // Use explicit API key selection check as required for Veo
  if (window.aistudio) {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
       await window.aistudio.openSelectKey();
       // Guidelines: assume key selection was successful after triggering openSelectKey and proceed
    }
  }

  try {
    // Guidelines: Create a new GoogleGenAI instance right before making an API call 
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    let operation;

    const config: any = {
      numberOfVideos: 1,
      resolution: resolution,
      aspectRatio: aspectRatio
    };

    if (imageBytes) {
      const cleanBase64 = imageBytes.replace(/^data:image\/\w+;base64,/, "");
      const mimeMatch = imageBytes.match(/^data:(image\/\w+);base64,/);
      const mimeType = mimeMatch ? mimeMatch[1] : 'image/png';

      operation = await ai.models.generateVideos({
        model: MODEL_NAMES.VIDEO_FAST,
        prompt: prompt || "Animate this image in a cinematic way.",
        image: {
          imageBytes: cleanBase64,
          mimeType: mimeType
        },
        config
      });
    } else {
      operation = await ai.models.generateVideos({
        model: MODEL_NAMES.VIDEO_FAST,
        prompt: prompt,
        config
      });
    }

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({operation: operation});
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) return null;

    // Guidelines: You must append an API key when fetching from the download link.
    const res = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    if (!res.ok) {
       const errText = await res.text();
       if (errText.includes("Requested entity was not found")) {
          if (window.aistudio) await window.aistudio.openSelectKey();
       }
       throw new Error("Failed to download video bytes");
    }
    const blob = await res.blob();
    return URL.createObjectURL(blob);

  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      if (window.aistudio) await window.aistudio.openSelectKey();
    }
    throw error;
  }
};

