  Key,
  RotateCcw
} from 'lucide-react';

const LOADING_MESSAGES = [
  "Initializing Veo creative engine...",
  "Analyzing visual descriptors and style cues...",
  "Synthesizing high-fidelity frames...",
  "Applying temporal coherence and physics...",
  "Finalizing cinematic render...",
  "Optimizing for your target aspect ratio...",
  "Hang tight, artistic perfection takes a moment..."
];

const SPEED_OPTIONS = [0.5, 0.75, 1, 1.25, 1.5, 2];

interface TimelineClip {
  id: string;
  type: 'video' | 'audio';
  url: string;
  name: string;
  duration: number;
  trimStart: number;
  trimEnd: number;
  timelineOffset: number;
  playbackSpeed: number;
}

export const VideoStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'create' | 'edit'>('create');
  const [hasApiKey, setHasApiKey] = useState(true);

  // --- GENERATOR STATE ---
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const [justAdded, setJustAdded] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);

  const previewVideoRef = useRef<HTMLVideoElement>(null);
  const editorFileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
    };
    checkKey();
  }, []);

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 5000);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey && window.aistudio) {
       await handleOpenKeyPicker();
    }

    setIsGenerating(true);
    setGeneratedVideoUrl(null);
    try {
      const url = await generateVideo(prompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
      }
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
         setHasApiKey(false);
         alert("Project mismatch or missing API key. Please select your paid API key again.");
      } else {
         alert("Video generation failed. Please try a different prompt.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const sendToEditor = () => {
    if (generatedVideoUrl) {
      addVideoToTimeline(generatedVideoUrl, `AI Clip ${timeline.length + 1}`);
      setJustAdded(true);
      setTimeout(() => {
        setJustAdded(false);
        setActiveTab('edit');
      }, 800);
    }
  };

  const addVideoToTimeline = (url: string, name: string) => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const duration = tempVid.duration || 10;

      setTimeline(prev => {
        // Calculate next offset based on the most recent state
        let nextOffset = 0;
        if (prev.length > 0) {
          const last = prev[prev.length - 1];
          nextOffset = last.timelineOffset + (last.trimEnd - last.trimStart) / last.playbackSpeed;
        }

        const newClip: TimelineClip = {
          id: Math.random().toString(36).substring(2, 11),
          type: 'video',
          url,
          name,
          duration,
          trimStart: 0,
          trimEnd: duration,
          timelineOffset: nextOffset,
          playbackSpeed: 1
        };

        const newTimeline = [...prev, newClip];
        recalculateTotalDuration(newTimeline);
        return newTimeline;
      });
    };
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const end = c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed;
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const clearTimeline = () => {
    if (confirm("Clear all clips from the current timeline?")) {
      setTimeline([]);
      setTotalDuration(0);
      setCurrentTime(0);
      setIsPlaying(false);
    }
  };

  const togglePlay = () => setIsPlaying(!isPlaying);

  const seek = (time: number) => {
    setCurrentTime(Math.max(0, Math.min(time, totalDuration)));
  };

  useEffect(() => {
    let animationFrameId: number;
    if (isPlaying) {
      const startTime = performance.now();
      const initialCurrentTime = currentTime;
      const animate = (now: number) => {
        const delta = (now - startTime) / 1000;
        const next = initialCurrentTime + delta;
        if (next >= totalDuration) {
          setIsPlaying(false);
          setCurrentTime(totalDuration);
        } else {
          setCurrentTime(next);
          animationFrameId = requestAnimationFrame(animate);
        }
      };
      animationFrameId = requestAnimationFrame(animate);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  // Sync Video Ref with currentTime
  useEffect(() => {
    if (previewVideoRef.current) {
       const activeClip = timeline.find(c => 
         c.type === 'video' && 
         currentTime >= c.timelineOffset && 
         currentTime <= (c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed)
       );
       if (activeClip) {
          if (previewVideoRef.current.src !== activeClip.url) {
            previewVideoRef.current.src = activeClip.url;
          }
          const internalTime = activeClip.trimStart + (currentTime - activeClip.timelineOffset) * activeClip.playbackSpeed;
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.2) {
             previewVideoRef.current.currentTime = internalTime;
          }
       }
    }
  }, [currentTime, timeline]);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in">
      <header className="flex items-center justify-between py-6 border-b border-zinc-800 shrink-0 mb-6">
