           <div className="flex-1 bg-black rounded-[3rem] relative flex items-center justify-center overflow-hidden border border-zinc-800 shadow-2xl">
              <video ref={previewVideoRef} className="max-h-full max-w-full" onEnded={() => setIsPlaying(false)} />

              {timeline.length === 0 && (
                <div className="text-zinc-900 flex flex-col items-center gap-4">
                   <Layers size={80} className="opacity-20" />
                   <p className="font-black uppercase tracking-[0.4em] text-xs opacity-40">Timeline Empty</p>
                </div>
              )}

              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-md border border-zinc-800/50 rounded-2xl px-6 py-3 flex items-center gap-6 shadow-2xl">
                 <div className="flex items-center gap-4">
                    <button onClick={() => seek(0)} className="p-2 text-zinc-500 hover:text-white transition-colors active-press"><SkipBack size={20} /></button>
                    <button onClick={togglePlay} className="p-3 bg-red-600 hover:bg-red-500 rounded-full text-white transition-all shadow-lg shadow-red-600/20 active-press">
                       {isPlaying ? <PauseCircle size={32} /> : <PlayCircle size={32} />}
