  Loader2, 
  RefreshCcw, 
  Twitter, 
  Mail, 
  FileText, 
  Copy, 
  Video, 
  Clock, 
  Sparkles, 
  Maximize2, 
  Minimize2, 
  Monitor,
  Check,
