import { GoogleGenAI, Type, Modality } from "@google/genai";
import { MODEL_NAMES, SYSTEM_INSTRUCTIONS } from '../constants';
import { VideoIdea, SeoResult, SocialPost, ThumbnailRating, CompetitorAnalysis, VideoAudit, RepurposedContent, KeywordMetrics, TrendResult, TitlePrediction, OutreachResult, CustomerPersona, NicheGap, TrendForecast } from '../types';

const getAiClient = (forceNew: boolean = false) => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found in environment variables");
  }
  return new GoogleGenAI({ apiKey });
};

// --- Shorts Architect ---
export const generateShortsScript = async (
  topic: string, 
  style: string, 
  pacing: 'Fast' | 'Standard',
  onChunk: (text: string) => void
) => {
  const ai = getAiClient();
  const prompt = `Topic: "${topic}". 
  Style: "${style}". 
  Requested Pacing: "${pacing}". 

  Generate a viral-ready Shorts script with visual production cues. 
  Ensure it follows the high-retention loop structure.`;

  const result = await ai.models.generateContentStream({
    model: MODEL_NAMES.TEXT_FAST, // Flash is best for rapid script iteration
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.SHORTS
    }
  });

  for await (const chunk of result) {
    if (chunk.text) onChunk(chunk.text);
  }
};

// --- Ideas ---
export const generateIdeas = async (niche: string, count: number = 5): Promise<VideoIdea[]> => {
  const ai = getAiClient();
  const prompt = `Generate ${count} viral YouTube video ideas for the niche: "${niche}". Ensure high click-through rate titles and intriguing hooks.`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_FAST,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.IDEAS,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            hook: { type: Type.STRING },
            score: { type: Type.NUMBER }
          },
          required: ["title", "hook", "score"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) return [];
  try {
    const ideas = JSON.parse(text) as VideoIdea[];
    return Array.isArray(ideas) ? ideas : [];
  } catch (e) {
    console.error("Failed to parse JSON", e);
    return [];
  }
};

// --- Script ---
export const generateScriptStream = async (
  title: string, 
  tone: string, 
  scriptType: string = 'standard',
  instructions: string,
  onChunk: (text: string) => void,
  useFastModel: boolean = false
) => {
  const ai = getAiClient();

  let structureGuide = "";
  switch(scriptType) {
    case 'storytelling':
      structureGuide = `\n**Structure: Storytelling (Documentary Style)**
      1. **The Hook (0-60s)**: Start in the middle of the action or a high-stakes moment. Create immediate curiosity.
      2. **The Context (Inciting Incident)**: Why does this matter? What is the goal?
      3. **The Journey (Rising Action)**: The struggle, the research, the "trying and failing".
      4. **The Climax**: The realization or the peak moment of the video.
      5. **Resolution & Takeaway**: What did we learn? Emotional connection.`;
      break;
    case 'whitepaper':
      structureGuide = `\n**Structure: White Paper / Deep Dive Research**
      1. **Abstract / Executive Summary**: Brief overview of the findings.
      2. **Problem Statement**: The core issue being analyzed.
      3. **Methodology & Deep Analysis**: Data-driven, research-backed breakdown. Use "Chapter" markers.
      4. **Evidence & Counter-arguments**: Address nuances.
      5. **Conclusion & Future Outlook**: Final verdict.`;
      break;
    case 'tutorial':
      structureGuide = `\n**Structure: Step-by-Step Tutorial**
      1. **Result Showcase**: Show what they will build/achieve first.
      2. **Prerequisites**: What is needed.
      3. **The Steps**: Clear, numbered steps (Step 1, Step 2...).
      4. **Common Pitfalls**: What to avoid.
      5. **Final Polish**: The finished result.`;
      break;
    default: // standard
      structureGuide = `\n**Structure: Standard High-Retention YouTube**
      1. **The Hook (0-30s)**: Visual & Verbal hook.
      2. **Intro**: Brief context.
      3. **Content Body**: 3-5 Key Points / Listicles.
      4. **Call to Action**: Mid-roll or end.
      5. **Outro**: Link to next video.`;
      break;
  }

  let prompt = `Write a YouTube video script for a video titled: "${title}". 
  \nTone: ${tone}.
  \nScript Type: ${scriptType}.
  ${structureGuide}`;

  if (instructions) prompt += `\n\nSpecific Context & User Instructions:\n${instructions}`;
  prompt += `\n\nEnsure the pacing matches the requested type. Use Markdown formatting.`;

  const result = await ai.models.generateContentStream({
    model: useFastModel ? MODEL_NAMES.TEXT_LITE : MODEL_NAMES.TEXT_SMART,
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.SCRIPT
    }
  });

  for await (const chunk of result) {
    if (chunk.text) onChunk(chunk.text);
  }
};

// --- SEO ---
export const generateSeo = async (topic: string): Promise<SeoResult> => {
  const ai = getAiClient();
  const prompt = `Perform a linguistic semantic mapping and generate metadata for a video about: "${topic}".`;

  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART, 
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.SEO,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          titles: { type: Type.ARRAY, items: { type: Type.STRING } },
          description: { type: Type.STRING },
          tags: { type: Type.ARRAY, items: { type: Type.STRING } },
          hashtags: { type: Type.ARRAY, items: { type: Type.STRING } },
          semanticClusters: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ["titles", "description", "tags", "hashtags", "semanticClusters"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");
  const res = JSON.parse(text) as SeoResult;
  return {
    ...res,
    titles: res.titles || [],
    tags: res.tags || [],
    hashtags: res.hashtags || [],
    semanticClusters: res.semanticClusters || []
  };
};

// --- Images (Standard, Pro & Imagen) ---
export const generateThumbnail = async (
  prompt: string, 
  style: string = 'Photorealistic', 
  mode: 'fast' | 'pro' | 'artistic' = 'fast',
  aspectRatio: string = '16:9',
  imageSize: string = '1K'
): Promise<string | null> => {

  // Mandatory API Key selection for Pro/Imagen
  if (mode !== 'fast' && window.aistudio) {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
       await window.aistudio.openSelectKey();
    }
  }

  const ai = getAiClient(mode !== 'fast');

  // Enhanced base prompt with advanced cinematography descriptors
  const enhancedPrompt = `Professional YouTube thumbnail Masterpiece.
  Subject Concept: ${prompt}. 
  Style: ${style}. 
  Technical Details: Ray-traced cinematic lighting, extreme sharpness, professional color grading, ultra-high dynamic range (HDR), volumetric lighting effects, deep rich blacks, and intricate micro-textures. 
  Composition: 8k resolution, photorealistic physics, clean composition without any text, watermarks, or logos. Focus on maximum visual click-through rate.`;

  try {
    if (mode === 'artistic') {
      const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: enhancedPrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: aspectRatio as any,
          outputMimeType: 'image/jpeg'
        }
      });
      const bytes = response.generatedImages?.[0]?.image?.imageBytes;
      return bytes ? `data:image/jpeg;base64,${bytes}` : null;
    }

    const model = mode === 'pro' ? MODEL_NAMES.IMAGE_PRO : MODEL_NAMES.IMAGE_FAST;
    const config: any = {
      imageConfig: {
        aspectRatio: aspectRatio,
      }
    };

    if (mode === 'pro') {
      config.imageConfig.imageSize = imageSize;
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: enhancedPrompt,
      config: config
    });

    // Correctly iterate through parts to find the image
    const parts = response.candidates?.[0]?.content?.parts;
    if (parts) {
      for (const part of parts) {
        if (part.inlineData && part.inlineData.data) {
           return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      if (window.aistudio) await window.aistudio.openSelectKey();
    }
    throw error;
  }
  return null;
};

export const enhanceThumbnailPrompt = async (prompt: string): Promise<string> => {
  const ai = getAiClient();
  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_SMART, 
