import React, { useState } from 'react';
import { Layout } from './components/Layout';
import { CreatorDashboard } from './views/CreatorDashboard';
import { DeveloperDashboard } from './views/DeveloperDashboard';
import { Projects } from './views/Projects';
import { IdeaGenerator } from './views/IdeaGenerator';
import { ScriptWriter } from './views/ScriptWriter';
import { ShortsGenerator } from './views/ShortsGenerator';
import { SeoOptimizer } from './views/SeoOptimizer';
import { ThumbnailGenerator } from './views/ThumbnailGenerator';
import { ThumbnailRater } from './views/ThumbnailRater';
import { CompetitorSpy } from './views/CompetitorSpy';
import { ChannelAudit } from './views/ChannelAudit';
import { MarketingScheduler } from './views/MarketingScheduler';
import { VideoStudio } from './views/VideoStudio';
import { AudioStudio } from './views/AudioStudio';
import { ResearchAssistant } from './views/ResearchAssistant';
import { LiveBrainstorm } from './views/LiveBrainstorm';
import { RepurposeEngine } from './views/RepurposeEngine';
import { KeywordInspector } from './views/KeywordInspector';
import { TrendWatcher } from './views/TrendWatcher';
import { TitleGenerator } from './views/TitleGenerator';
import { OutreachHub } from './views/OutreachHub';
import { EmailMarketing } from './views/EmailMarketing';
import { MarketStrategist } from './views/MarketStrategist';
import { About } from './views/About';
import { Upgrade } from './views/Upgrade';
import { Auth } from './views/Auth';
import { ToolType } from './types';
import { AuthProvider, useAuth } from './auth/AuthContext';
import { Loader2 } from 'lucide-react';

const AppContent = () => {
  const { user, isLoading, checkPlanStatus } = useAuth();
  const [currentTool, setCurrentTool] = useState<ToolType>(ToolType.DASHBOARD);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-[#09090b] flex items-center justify-center">
        <Loader2 className="animate-spin text-red-500" size={32} />
      </div>
    );
  }

  if (!user) {
    return <Auth />;
  }

  const { isValid } = checkPlanStatus();

  if (!isValid && currentTool !== ToolType.UPGRADE) {
    return <Upgrade />;
  }

  const renderTool = () => {
    if (currentTool === ToolType.UPGRADE) {
      return <Upgrade />;
    }

    if (!isValid) return <Upgrade />;

    switch (currentTool) {
      case ToolType.DASHBOARD:
        return <CreatorDashboard onNavigate={setCurrentTool} />;
      case ToolType.DEV_DASHBOARD:
        return <DeveloperDashboard />;
      case ToolType.ABOUT:
        return <About />;
      case ToolType.PROJECTS:
        return <Projects />;
      case ToolType.IDEAS:
        return <IdeaGenerator />;
      case ToolType.SCRIPT:
        return <ScriptWriter />;
      case ToolType.SHORTS_GENERATOR:
        return <ShortsGenerator />;
      case ToolType.SEO:
        return <SeoOptimizer />;
      case ToolType.THUMBNAIL:
        return <ThumbnailGenerator />;
      case ToolType.THUMBNAIL_RATER:
        return <ThumbnailRater />;
      case ToolType.COMPETITOR_SPY:
        return <CompetitorSpy />;
      case ToolType.CHANNEL_AUDIT:
        return <ChannelAudit />;
      case ToolType.VIDEO:
        return <VideoStudio />;
      case ToolType.AUDIO:
        return <AudioStudio />;
      case ToolType.RESEARCH:
        return <ResearchAssistant />;
      case ToolType.LIVE:
        return <LiveBrainstorm />;
      case ToolType.MARKETING:
        return <MarketingScheduler />;
      case ToolType.REPURPOSE:
        return <RepurposeEngine onNavigate={setCurrentTool} />;
      case ToolType.KEYWORD_INSPECTOR:
        return <KeywordInspector />;
      case ToolType.TREND_WATCHER:
        return <TrendWatcher />;
      case ToolType.TITLE_GENERATOR:
        return <TitleGenerator />;
      case ToolType.OUTREACH:
        return <OutreachHub />;
      case ToolType.EMAIL_MARKETING:
        return <EmailMarketing />;
      case ToolType.MARKET_STRATEGIST:
        return <MarketStrategist />;
      default:
        return <CreatorDashboard onNavigate={setCurrentTool} />;
    }
  };

  return (
    <Layout currentTool={currentTool} onNavigate={setCurrentTool}>
      {renderTool()}
    </Layout>
  );
};

function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { generateShortsScript } from '../services/gemini';
import { 
  Loader2, 
  Smartphone, 
  Zap, 
  Clock, 
  Copy, 
  Maximize2, 
  Minimize2, 
  Sparkles, 
  Video, 
  FileText,
  Play,
  RotateCcw
} from 'lucide-react';
import { useAuth } from '../auth/AuthContext';

const SHORT_STYLES = [
  { id: 'cinematic', label: 'Cinematic Story', desc: 'Dramatic lighting and high production feel.' },
  { id: 'kinetic', label: 'Kinetic Typography', desc: 'Fast text, energetic music, and bold colors.' },
  { id: 'documentary', label: 'Mini Docu', desc: 'Informative, fast facts, and clean b-roll.' },
  { id: 'sketch', label: 'POV Sketch', desc: 'Relatable characters and punchy dialogue.' },
  { id: 'educational', label: 'How-to Blast', desc: 'Rapid steps and satisfying results.' }
];

export const ShortsGenerator: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [style, setStyle] = useState('cinematic');
  const [pacing, setPacing] = useState<'Fast' | 'Standard'>('Fast');
  const [script, setScript] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [teleprompterMode, setTeleprompterMode] = useState(false);

  const { incrementStat } = useAuth();
  const scriptEndRef = useRef<HTMLDivElement>(null);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim()) return;

    setIsGenerating(true);
    setScript('');

    try {
      await generateShortsScript(topic, style, pacing, (chunk) => {
        setScript(prev => prev + chunk);
      });
      incrementStat('scriptsWritten');
    } catch (err) {
      console.error(err);
      setScript("[Error generating script. Please check your connection and try again.]");
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (scriptEndRef.current && !teleprompterMode) {
      scriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [script, teleprompterMode]);

  // Calculate estimated time (words per minute for shorts is high)
  const spokenTextOnly = script.replace(/\[.*?\]/g, '').trim();
  const wordCount = spokenTextOnly.split(/\s+/).filter(w => w.length > 0).length;
  const estSeconds = Math.round((wordCount / (pacing === 'Fast' ? 165 : 135)) * 60);
  const isOverLimit = estSeconds > 60;

  const copyScript = () => {
    navigator.clipboard.writeText(script);
    alert("Full script copied to clipboard!");
  };

  const reset = () => {
    setTopic('');
    setScript('');
  };

  return (
    <div className={`h-full flex flex-col gap-8 animate-fade-in ${teleprompterMode ? 'fixed inset-0 z-50 bg-[#09090b] p-8 md:p-20' : 'pb-10'}`}>

      {!teleprompterMode && (
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 shrink-0">
          <div>
            <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
              <Smartphone className="text-red-500" /> Shorts Architect
            </h2>
            <p className="text-zinc-400 text-sm">Design viral vertical content with high-retention logic.</p>
          </div>
          <div className="flex gap-2">
            {script && (
              <button 
                onClick={reset}
                className="p-3 bg-zinc-900 border border-zinc-800 text-zinc-500 hover:text-white rounded-2xl transition-all"
                title="New Session"
              >
                <RotateCcw size={18} />
              </button>
            )}
          </div>
        </header>
      )}

      <div className={`flex-1 flex flex-col md:flex-row gap-8 min-h-0 ${teleprompterMode ? 'w-full max-w-6xl mx-auto' : ''}`}>

        {/* Left: Input Panel */}
        {!teleprompterMode && (
          <div className="w-full md:w-[400px] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar pb-4">
            <form onSubmit={handleGenerate} className="bg-zinc-900 border border-zinc-800 p-8 rounded-[2.5rem] space-y-8 shadow-2xl">
              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Video Core Topic</label>
                <textarea
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  placeholder="What is this Short about? (e.g. 3 AI tools that feel illegal to know)"
                  className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 focus:ring-2 focus:ring-red-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed"
                />
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Artistic Style</label>
                <div className="grid grid-cols-1 gap-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
                  {SHORT_STYLES.map(s => (
                    <button
                      key={s.id}
                      type="button"
                      onClick={() => setStyle(s.id)}
                      className={`text-left p-3 rounded-xl border transition-all ${style === s.id ? 'bg-red-500/10 border-red-500 text-red-500 shadow-lg' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
                    >
                      <p className="text-xs font-bold">{s.label}</p>
                      <p className="text-[10px] opacity-60 font-medium truncate">{s.desc}</p>
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Narration Pacing</label>
                <div className="flex bg-zinc-950 border border-zinc-800 rounded-2xl p-1">
                  <button
                    type="button"
                    onClick={() => setPacing('Fast')}
                    className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${pacing === 'Fast' ? 'bg-zinc-800 text-white shadow-md' : 'text-zinc-500 hover:text-white'}`}
                  >
                    Aggressive
                  </button>
                  <button
                    type="button"
                    onClick={() => setPacing('Standard')}
                    className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${pacing === 'Standard' ? 'bg-zinc-800 text-white shadow-md' : 'text-zinc-500 hover:text-white'}`}
                  >
                    Steady
                  </button>
                </div>
              </div>

              <button
                type="submit"
                disabled={isGenerating || !topic}
                className={`w-full py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-widest transition-all shadow-xl flex items-center justify-center gap-3 active-press ${isGenerating ? 'bg-zinc-800 text-zinc-600' : 'bg-red-600 hover:bg-red-500 text-white shadow-red-600/20'}`}
              >
                {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <><Sparkles size={18} /> Sculpt Script</>}
              </button>
            </form>

            <div className="p-6 bg-zinc-900/50 border border-zinc-800 rounded-[2rem] flex items-start gap-4">
               <div className="p-3 bg-blue-500/10 rounded-2xl text-blue-400">
                  <Zap size={20} />
               </div>
               <div>
                  <h4 className="text-[10px] font-bold text-white uppercase tracking-widest mb-1">Architecture Tip</h4>
                  <p className="text-[11px] text-zinc-500 leading-relaxed italic">
                    "Fast pacing requires 3 scene changes per 5 seconds. Use our generated visual cues to stay ahead of the curve."
                  </p>
               </div>
            </div>
          </div>
        )}

        {/* Right: Output Stage */}
        <div className={`flex-1 flex flex-col gap-6 min-w-0 transition-all duration-500`}>

          {/* Stats Bar */}
          {script && !teleprompterMode && (
            <div className="flex items-center gap-6 bg-zinc-900 border border-zinc-800 p-4 rounded-[1.5rem] shadow-inner shrink-0">
               <div className="flex items-center gap-2">
                  <Clock size={16} className={isOverLimit ? 'text-red-500' : 'text-green-500'} />
                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">Runtime Est.</span>
                    <span className={`text-sm font-black ${isOverLimit ? 'text-red-500' : 'text-white'}`}>{estSeconds}s {isOverLimit && '(FAIL)'}</span>
                  </div>
               </div>
               <div className="w-px h-8 bg-zinc-800"></div>
               <div className="flex items-center gap-2">
                  <FileText size={16} className="text-blue-500" />
                  <div className="flex flex-col">
                    <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">Density</span>
                    <span className="text-sm font-black text-white">{wordCount} Words</span>
                  </div>
               </div>
               <div className="ml-auto flex gap-2">
                  <button onClick={copyScript} className="p-2.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded-xl transition-all"><Copy size={16} /></button>
                  <button onClick={() => setTeleprompterMode(true)} className="p-2.5 bg-red-600 hover:bg-red-500 text-white rounded-xl transition-all shadow-lg shadow-red-600/20"><Maximize2 size={16} /></button>
               </div>
            </div>
          )}

          <div className={`flex-1 bg-zinc-950 border border-zinc-900 rounded-[3rem] shadow-inner relative overflow-hidden group flex flex-col ${teleprompterMode ? 'border-none' : ''}`}>

             {teleprompterMode && (
               <div className="shrink-0 flex items-center justify-between mb-12">
                  <div className="flex items-center gap-4">
                     <div className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center animate-pulse">
                        <Play size={24} fill="white" className="ml-1" />
                     </div>
                     <h3 className="text-2xl font-black uppercase tracking-[0.2em] text-white">Live Teleprompter</h3>
                  </div>
                  <button 
                    onClick={() => setTeleprompterMode(false)}
                    className="p-4 bg-zinc-900 border border-zinc-800 text-white rounded-2xl hover:bg-zinc-800 transition-all"
                  >
                     <Minimize2 size={24} />
                  </button>
               </div>
             )}

             <div className="flex-1 overflow-y-auto p-8 md:p-12 custom-scrollbar">
                {!script && !isGenerating ? (
                   <div className="h-full flex flex-col items-center justify-center text-zinc-800 gap-6 opacity-30">
                      <div className="w-40 h-40 rounded-[2.5rem] border-4 border-dashed border-zinc-800 flex items-center justify-center">
                         <Smartphone size={80} strokeWidth={1} />
                      </div>
                      <p className="font-black uppercase text-sm tracking-[0.4em]">Vertical Workspace Empty</p>
                   </div>
                ) : isGenerating && !script ? (
                   <div className="h-full flex flex-col items-center justify-center gap-8 text-red-500">
                      <div className="relative">
                         <Loader2 className="animate-spin w-20 h-20" strokeWidth={1} />
                         <div className="absolute inset-0 bg-red-500 blur-3xl opacity-10 animate-pulse"></div>
                      </div>
                      <p className="text-xl font-black text-white tracking-tight animate-pulse uppercase">Compressing Narrative</p>
                   </div>
                ) : (
                   <div className={`${teleprompterMode ? 'max-w-4xl mx-auto text-5xl md:text-7xl font-black leading-tight space-y-16 pb-64' : 'text-lg font-bold leading-relaxed space-y-6'} text-white transition-all duration-300`}>
                      {script.split(/(\[.*?\])/g).map((part, i) => (
                        part.startsWith('[') ? (
                          <div key={i} className={`flex items-center gap-3 bg-red-600/10 text-red-500 border border-red-600/20 rounded-2xl w-fit ${teleprompterMode ? 'px-8 py-4 text-2xl' : 'px-4 py-2 text-[10px] uppercase tracking-widest'}`}>
                             <Video size={teleprompterMode ? 24 : 14} />
                             {part.slice(1, -1)}
                          </div>
                        ) : (
                          <p key={i} className="whitespace-pre-wrap">{part}</p>
                        )
                      ))}
                      <div ref={scriptEndRef} />
                   </div>
                )}
             </div>

             {/* Bottom Fade Gradient for Teleprompter */}
             {teleprompterMode && (
                <div className="absolute bottom-0 left-0 right-0 h-64 bg-gradient-to-t from-[#09090b] to-transparent pointer-events-none"></div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

