// --- Images (Standard, Pro & Imagen) ---
export const generateThumbnail = async (
  prompt: string, 
  style: string = 'Photorealistic', 
  mode: 'fast' | 'pro' | 'artistic' = 'fast',
  aspectRatio: string = '16:9',
  imageSize: string = '1K'
): Promise<string | null> => {

  // Mandatory API Key selection for Pro/Imagen
  if (mode !== 'fast' && window.aistudio) {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
       await window.aistudio.openSelectKey();
    }
  }

  const ai = getAiClient(mode !== 'fast');

  // Enhanced base prompt with advanced cinematography descriptors
  const enhancedPrompt = `Professional YouTube thumbnail Masterpiece.
  Subject Concept: ${prompt}. 
  Style: ${style}. 
  Technical Details: Ray-traced cinematic lighting, extreme sharpness, professional color grading, ultra-high dynamic range (HDR), volumetric lighting effects, deep rich blacks, and intricate micro-textures. 
  Composition: 8k resolution, photorealistic physics, clean composition without any text, watermarks, or logos. Focus on maximum visual click-through rate.`;

  try {
    if (mode === 'artistic') {
      const response = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: enhancedPrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: aspectRatio as any,
          outputMimeType: 'image/jpeg'
        }
      });
      const bytes = response.generatedImages?.[0]?.image?.imageBytes;
      return bytes ? `data:image/jpeg;base64,${bytes}` : null;
    }

    const model = mode === 'pro' ? MODEL_NAMES.IMAGE_PRO : MODEL_NAMES.IMAGE_FAST;
    const config: any = {
      imageConfig: {
        aspectRatio: aspectRatio,
      }
    };

    if (mode === 'pro') {
      config.imageConfig.imageSize = imageSize;
    }

    const response = await ai.models.generateContent({
      model: model,
      contents: enhancedPrompt,
      config: config
    });

    // Correctly iterate through parts to find the image
    const parts = response.candidates?.[0]?.content?.parts;
    if (parts) {
      for (const part of parts) {
        if (part.inlineData && part.inlineData.data) {
           return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
  } catch (error: any) {
    if (error.message?.includes("Requested entity was not found")) {
      if (window.aistudio) await window.aistudio.openSelectKey();
    }
    throw error;
  }
  return null;
};

