           </div>

           {/* Timeline Control Panel */}
           <div className="h-[45%] bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl">
              <div className="h-16 border-b border-zinc-800 flex items-center justify-between px-8 bg-zinc-950/50">
                 <h3 className="text-xs font-black uppercase tracking-widest text-zinc-400">Master Sequence</h3>
                 <div className="flex items-center gap-4">
                    <button 
                      onClick={clearTimeline}
                      className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2 text-zinc-500 hover:text-red-500 transition-colors px-4 py-2"
                    >
                      <RotateCcw size={14} /> Reset
                    </button>
                    <button 
                      onClick={() => editorFileInputRef.current?.click()}
                      className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-white px-5 py-2.5 rounded-xl border border-zinc-700 transition-all active-press"
                    >
                      <Plus size={14} /> Import Media
                    </button>
                    <input type="file" ref={editorFileInputRef} onChange={(e) => {
                       const file = e.target.files?.[0];
                       if (file) addVideoToTimeline(URL.createObjectURL(file), file.name);
                    }} className="hidden" accept="video/*" />
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-black/20 custom-scrollbar">
                 {timeline.length === 0 ? (
                   <div className="h-full flex flex-col items-center justify-center text-zinc-800">
                      <p className="text-sm font-bold uppercase tracking-widest opacity-30 italic">No tracks detected in current workspace</p>
                   </div>
                 ) : (
                   timeline.map((clip) => (
                     <div key={clip.id} className="group relative bg-zinc-900 border border-zinc-800/60 rounded-[2rem] p-5 flex gap-6 items-center hover:border-zinc-700 transition-all hover:shadow-xl">
                        <div className={`p-5 rounded-2xl shrink-0 transition-transform duration-500 group-hover:rotate-6 ${clip.type === 'video' ? 'bg-blue-600/10 text-blue-500 shadow-inner' : 'bg-purple-600/10 text-purple-500 shadow-inner'}`}>
                           {clip.type === 'video' ? <Film size={28} strokeWidth={1.5} /> : <AudioLines size={28} strokeWidth={1.5} />}
                        </div>

                        <div className="flex-1 min-w-0 space-y-4">
                           <div className="flex justify-between items-start">
                              <div className="min-w-0">
                                 <h4 className="text-base font-extrabold text-white truncate group-hover:text-red-500 transition-colors">{clip.name}</h4>
                                 <p className="text-[9px] text-zinc-500 uppercase font-black tracking-[0.2em] mt-1">{clip.type} source · {clip.duration.toFixed(1)}s</p>
                              </div>
                              <button 
                                onClick={() => {
                                   const updated = timeline.filter(c => c.id !== clip.id);
                                   setTimeline(updated);
                                   recalculateTotalDuration(updated);
                                }} 
                                className="p-2.5 text-zinc-600 hover:text-red-500 transition-all bg-zinc-950 rounded-xl border border-zinc-800 active-press"
                              >
                                 <Trash2 size={16} />
                              </button>
                           </div>

                           <div className="grid grid-cols-4 gap-4 items-end">
                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1">Offset (s)</span>
                                 <div className="bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2">
                                    <input 
                                      type="number" 
                                      value={clip.timelineOffset} 
                                      step={0.1}
                                      onChange={(e) => {
                                        const val = parseFloat(e.target.value) || 0;
                                        setTimeline(prev => {
                                          const next = prev.map(c => c.id === clip.id ? { ...c, timelineOffset: val } : c);
                                          recalculateTotalDuration(next);
                                          return next;
                                        });
                                      }}
                                      className="bg-transparent border-none outline-none text-xs font-bold text-white w-full" 
                                    />
                                 </div>
                              </div>

                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1 flex items-center gap-1">
                                   <Gauge size={10} /> Speed
                                 </span>
                                 <div className="relative">
                                    <select 
                                         value={clip.playbackSpeed} 
                                         onChange={(e) => {
                                           const val = parseFloat(e.target.value) || 1;
                                           setTimeline(prev => {
                                             const next = prev.map(c => c.id === clip.id ? { ...c, playbackSpeed: val } : c);
                                             recalculateTotalDuration(next);
                                             return next;
                                           });
                                         }}
                                         className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs font-bold text-white appearance-none cursor-pointer focus:border-red-500 transition-colors"
                                    >
                                          {SPEED_OPTIONS.map(s => <option key={s} value={s}>{s}x</option>)}
                                    </select>
                                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                                       <Zap size={10} fill="currentColor" />
                                    </div>
                                 </div>
                              </div>

                              <div className="col-span-2 space-y-2">
                                 <div className="flex justify-between text-[9px] font-black text-zinc-700 uppercase tracking-widest">
                                    <span>Duration Scale</span>
                                    <span className="text-zinc-500">{((clip.trimEnd - clip.trimStart) / clip.playbackSpeed).toFixed(1)}s runtime</span>
                                 </div>
                                 <div className="h-1.5 w-full bg-zinc-950 rounded-full overflow-hidden relative border border-zinc-800/50 shadow-inner">
                                    <div 
                                      className={`absolute top-0 bottom-0 ${clip.type === 'video' ? 'bg-red-600' : 'bg-blue-600'} transition-all duration-300 shadow-[0_0_10px_rgba(239,68,68,0.3)]`} 
                                      style={{ left: '0%', width: '100%' }}
                                    ></div>
                                 </div>
                              </div>
                           </div>
                        </div>
                     </div>
                   ))
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { generateShortsScript } from '../services/gemini';
import { 
  Loader2, 
  Smartphone, 
  Zap, 
  Clock, 
  Copy, 
  Maximize2, 
  Minimize2, 
  Sparkles, 
  Video, 
  FileText,
  Play,
  RotateCcw,
  BookOpen,
  ChevronDown,
  Check
} from 'lucide-react';
import { useAuth } from '../auth/AuthContext';

const SHORT_STYLES = [
  { id: 'cinematic', label: 'Cinematic Story', desc: 'Dramatic lighting and high production feel.' },
  { id: 'kinetic', label: 'Kinetic Typography', desc: 'Fast text, energetic music, and bold colors.' },
  { id: 'documentary', label: 'Mini Docu', desc: 'Informative, fast facts, and clean b-roll.' },
  { id: 'sketch', label: 'POV Sketch', desc: 'Relatable characters and punchy dialogue.' },
  { id: 'educational', label: 'How-to Blast', desc: 'Rapid steps and satisfying results.' }
];

const SHORTS_PRESETS = [
  {
    id: 'ranktica-tutorial',
    label: 'Ranktica Walkthrough',
    topic: 'How to use Ranktica AI for YouTube Automation (Quick Tutorial)',
    style: 'educational',
    pacing: 'Fast' as const
  },
  {
    id: 'ai-news',
    label: 'AI News Update',
    topic: 'Breaking AI news: Google just released a new Gemini model that changes everything.',
    style: 'documentary',
    pacing: 'Fast' as const
  },
  {
    id: 'productivity-hack',
    label: 'Productivity Hack',
    topic: 'One simple trick to double your output as a creator using AI agents.',
    style: 'kinetic',
    pacing: 'Fast' as const
  }
];

export const ShortsGenerator: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [style, setStyle] = useState('cinematic');
  const [pacing, setPacing] = useState<'Fast' | 'Standard'>('Fast');
  const [script, setScript] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [teleprompterMode, setTeleprompterMode] = useState(false);
  const [showPresets, setShowPresets] = useState(false);

  const { incrementStat } = useAuth();
  const scriptEndRef = useRef<HTMLDivElement>(null);

  const applyPreset = (p: typeof SHORTS_PRESETS[0]) => {
    setTopic(p.topic);
    setStyle(p.style);
    setPacing(p.pacing);
    setShowPresets(false);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim()) return;

    setIsGenerating(true);
    setScript('');

    try {
      await generateShortsScript(topic, style, pacing, (chunk) => {
        setScript(prev => prev + chunk);
      });
      incrementStat('scriptsWritten');
    } catch (err) {
      console.error(err);
      setScript("[Error generating script. Please check your connection and try again.]");
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (scriptEndRef.current && !teleprompterMode) {
      scriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [script, teleprompterMode]);

  const spokenTextOnly = script.replace(/\[.*?\]/g, '').trim();
  const wordCount = spokenTextOnly.split(/\s+/).filter(w => w.length > 0).length;
  const estSeconds = Math.round((wordCount / (pacing === 'Fast' ? 165 : 135)) * 60);
  const isOverLimit = estSeconds > 60;

  const copyScript = () => {
    navigator.clipboard.writeText(script);
    alert("Full script copied to clipboard!");
  };

  const reset = () => {
    setTopic('');
    setScript('');
  };

  return (
    <div className={`h-full flex flex-col gap-8 animate-fade-in ${teleprompterMode ? 'fixed inset-0 z-50 bg-[#09090b] p-8 md:p-20' : 'pb-10'}`}>

      {!teleprompterMode && (
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 shrink-0">
          <div>
            <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
              <Smartphone className="text-red-500" /> Shorts Architect
            </h2>
            <p className="text-zinc-400 text-sm">Design viral vertical content with high-retention logic.</p>
          </div>
          <div className="flex gap-2">
            <div className="relative">
              <button 
                onClick={() => setShowPresets(!showPresets)}
                className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-5 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all border border-zinc-800"
              >
                <BookOpen size={16} /> Presets <ChevronDown size={14} className={showPresets ? 'rotate-180 transition-transform' : 'transition-transform'} />
              </button>
              {showPresets && (
                <div className="absolute top-full right-0 mt-3 w-64 bg-[#0f0f12] border border-zinc-800 rounded-2xl shadow-2xl z-50 overflow-hidden animate-scale-in glass-morphism">
                   <div className="p-3 border-b border-zinc-800 text-[10px] font-black uppercase text-zinc-500 tracking-widest">Select Template</div>
                   {SHORTS_PRESETS.map(p => (
                     <button
                       key={p.id}
                       onClick={() => applyPreset(p)}
                       className="w-full text-left px-4 py-3 hover:bg-red-500/10 hover:text-white text-zinc-400 text-sm font-medium border-b border-zinc-800 last:border-0 transition-colors"
                     >
                       {p.label}
                     </button>
                   ))}
                </div>
              )}
            </div>
            {script && (
              <button 
                onClick={reset}
                className="p-3 bg-zinc-900 border border-zinc-800 text-zinc-500 hover:text-white rounded-2xl transition-all"
                title="New Session"
              >
                <RotateCcw size={18} />
              </button>
            )}
          </div>
        </header>
      )}

      <div className={`flex-1 flex flex-col md:flex-row gap-8 min-h-0 ${teleprompterMode ? 'w-full max-w-6xl mx-auto' : ''}`}>

        {/* Left: Input Panel */}
        {!teleprompterMode && (
          <div className="w-full md:w-[400px] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar pb-4">
            <form onSubmit={handleGenerate} className="bg-zinc-900 border border-zinc-800 p-8 rounded-[2.5rem] space-y-8 shadow-2xl">
              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Video Core Topic</label>
                <textarea
                  value={topic}
