export const generateThumbnail = async (prompt: string, style: string, mode: string, aspectRatio: string, imageSize: string) => {
  const ai = getAiClient(mode !== 'fast');
  const response = await ai.models.generateContent({
    model: mode === 'pro' ? MODEL_NAMES.IMAGE_PRO : MODEL_NAMES.IMAGE_FAST,
    contents: `YouTube Thumbnail: ${prompt}. Style: ${style}.`,
    config: { 
      imageConfig: { 
        aspectRatio: aspectRatio as any,
        imageSize: imageSize as any
      } 
    }
  });
  const parts = response.candidates?.[0]?.content?.parts;
  if (parts) { for (const part of parts) { if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`; } }
  return null;
};

