  const [showPresets, setShowPresets] = useState(false);
  const [prompterSpeed, setPrompterSpeed] = useState(1);
  const [recentScripts, setRecentScripts] = useState<Array<{topic: string, script: string}>>([
    {
      topic: 'AI in Marketing',
      script: `[Visual: Neon "AI" text flickering over a traditional marketing billboard]\n**Marketing is changing forever, and if you’re not using AI, you’re already behind.**\n\n[Visual: Screen recording of Ranktica's Market Strategist building a persona]\n**Step 1: Hyper-Personalization. AI can now build a 40-point persona of your customer in seconds. No more guessing.**\n\n[Visual: Fast montage of AI-generated thumbnails with high CTR scores]\n**Step 2: Predictive Performance. Before you even post, AI models can predict your Click-Through Rate with 90% accuracy.**\n\n[Visual: Automated email blast sending 1,000 emails instantly]\n**Step 3: Infinite Scale. Reach thousands with personalized outreach without hiring a single employee.**\n\n[Visual: Hand clicking 'Sign Up' on Ranktica AI]\n**The future of marketing is autonomous. Start your AI journey at Ranktica.ai today!**`
    }
  ]);

  const { incrementStat } = useAuth();
  const scriptEndRef = useRef<HTMLDivElement>(null);

  const applyPreset = (p: typeof SHORTS_PRESETS[0]) => {
    setTopic(p.topic);
    setStyle(p.style);
    setPacing(p.pacing);
    setShowPresets(false);
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!topic.trim()) return;

    setIsGenerating(true);
    setScript('');

    try {
      let fullScript = '';
      await generateShortsScript(topic, style, pacing, (chunk) => {
        setScript(prev => prev + chunk);
        fullScript += chunk;
      });
      incrementStat('scriptsWritten');
      setRecentScripts(prev => [{topic, script: fullScript}, ...prev].slice(0, 5));
    } catch (err) {
      console.error(err);
      setScript("[Error generating script. Please check your connection and try again.]");
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (scriptEndRef.current && !teleprompterMode) {
      scriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [script, teleprompterMode]);

  const spokenTextOnly = script.replace(/\[.*?\]/g, '').trim();
  const wordCount = spokenTextOnly.split(/\s+/).filter(w => w.length > 0).length;
  const estSeconds = Math.round((wordCount / (pacing === 'Fast' ? 165 : 135)) * 60);
  const isOverLimit = estSeconds > 60;

  const copyScript = () => {
    navigator.clipboard.writeText(script);
    alert("Full script copied to clipboard!");
  };

  const reset = () => {
    setTopic('');
    setScript('');
