               </div>
            </div>
          )}

          <div className={`flex-1 bg-zinc-950 border border-zinc-900 rounded-[3rem] shadow-inner relative overflow-hidden group flex flex-col ${teleprompterMode ? 'border-none' : ''}`}>

             {teleprompterMode && (
               <div className="shrink-0 flex items-center justify-between mb-12">
                  <div className="flex items-center gap-4">
                     <div className="w-12 h-12 bg-red-600 rounded-full flex items-center justify-center animate-pulse">
                        <Play size={24} fill="white" className="ml-1" />
                     </div>
                     <div>
                        <h3 className="text-2xl font-black uppercase tracking-[0.2em] text-white">Live Teleprompter</h3>
                        <div className="flex items-center gap-3 mt-1">
                           <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1"><Timer size={10} /> Reading Speed:</span>
                           <div className="flex gap-1">
                              {[1, 1.25, 1.5].map(s => (
                                <button 
                                  key={s} 
                                  onClick={() => setPrompterSpeed(s)}
                                  className={`px-2 py-0.5 rounded text-[9px] font-black transition-all ${prompterSpeed === s ? 'bg-red-600 text-white' : 'bg-zinc-800 text-zinc-500 hover:text-white'}`}
                                >
