];

export const ScriptWriter: React.FC = () => {
  const [title, setTitle] = useState('');
  const [instructions, setInstructions] = useState('');
  const [tone, setTone] = useState('Engaging & Fun');
  const [scriptType, setScriptType] = useState('standard');
  const [script, setScript] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showPresets, setShowPresets] = useState(false);
  const [library, setLibrary] = useState<Array<{title: string, content: string, date: number}>>([
    {
      title: 'How to use Ranktica AI for YouTube Automation',
      date: Date.now(),
      content: `# How to use Ranktica AI for YouTube Automation\n\n**[0:00 - 0:15] THE HOOK**\n**"Ever feel like the YouTube algorithm is a puzzle you just can't solve? You've got the passion, but the research, the scripting, and the editing are eating up all your time. What if I told you that you could automate the entire process with one single dashboard? Welcome to Ranktica AI."**\n\n**[0:15 - 0:45] THE IDEA GENERATOR**\n**"It all starts with a spark. In the Viral Idea Lab, you don't just guess what's going to work. You enter your niche, and our Gemini 3 Pro model analyzes current trends to give you ideas with a calculated 'Viral Potential Score'. It even writes the hook for you."**\n\n**[0:45 - 1:15] THE SCRIPT WRITER**\n**"Once you have your winner, head over to the Script Writer. This isn't just generic AI text. It uses high-retention logic to structure your video. Whether it's a deep-dive documentary or a fast-paced tutorial, Ranktica formats it for maximum watch time."**\n\n**[1:15 - 1:45] SEO & CTR OPTIMIZATION**\n**"But a great video is useless if no one clicks. Our SEO Vision Studio maps your content to Google’s Knowledge Graph, finding the exact semantic clusters that trigger the algorithm. Pair that with our Thumbnail Studio to generate high-CTR visuals and use the CTR Rater to verify your design before you publish."**\n\n**[1:45 - 2:15] AUTOMATION SUITE**\n**"Need to scale across platforms? The Repurpose Engine takes your long-form script and turns it into a Twitter thread, a newsletter, and a 60-second Short instantly. You can even generate cinematic B-roll using our Veo-powered Video Studio."**\n\n**[2:15 - 2:30] OUTRO**\n**"YouTube Automation isn't about being lazy—it's about being strategic. Scale your channel, reclaim your time, and start your viral journey at Ranktica.ai today."**`
    }
  ]);

  const scriptEndRef = useRef<HTMLDivElement>(null);
  const instructionsRef = useRef<HTMLTextAreaElement>(null);
  const { incrementStat } = useAuth();
  const hasIncrementedRef = useRef(false);

  const applyPreset = (p: typeof SCRIPT_PRESETS[0]) => {
    setTitle(p.title);
    setTone(p.tone);
    setScriptType(p.type);
    setInstructions(p.instructions);
    setShowPresets(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    setIsGenerating(true);
    setScript('');
    hasIncrementedRef.current = false;

    try {
      let fullContent = '';
      await generateScriptStream(title, tone, scriptType, instructions, (chunk) => {
        setScript(prev => {
            if (!hasIncrementedRef.current && prev.length > 50) {
                incrementStat('scriptsWritten');
                hasIncrementedRef.current = true;
            }
            fullContent += chunk;
            return prev + chunk;
        });
      });
      setLibrary(prev => [{title, content: fullContent, date: Date.now()}, ...prev].slice(0, 10));
    } catch (err) {
      console.error(err);
      setScript(prev => prev + "\n\n[Error generating script. Please try again.]");
    } finally {
      setIsGenerating(false);
    }
  };

  useEffect(() => {
    if (scriptEndRef.current) {
      scriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [script]);

  const handleDownload = () => {
    const blob = new Blob([script], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${title.replace(/[^a-z0-9]/gi, '_').toLowerCase()}_script.md`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const insertFormat = (startTag: string, endTag: string = '') => {
    const textarea = instructionsRef.current;
    if (!textarea) return;

    const start = textarea.selectionStart;
    const end = textarea.selectionEnd;
    const text = textarea.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + startTag + selection + endTag + after;
    setInstructions(newText);

    setTimeout(() => {
      textarea.focus();
      textarea.setSelectionRange(start + startTag.length, end + startTag.length);
    }, 0);
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col md:flex-row gap-6 animate-fade-in pb-10">
      {/* Configuration Panel */}
      <div className="w-full md:w-[380px] space-y-6 flex flex-col shrink-0">
        <div className="flex items-center justify-between">
          <div>
            <h2 className="text-2xl font-black text-white mb-1">Script Writer</h2>
            <p className="text-zinc-500 text-[10px] font-bold uppercase tracking-widest">Architectural Studio</p>
          </div>
          <div className="relative">
            <button 
              onClick={() => setShowPresets(!showPresets)}
              className="flex items-center gap-2 bg-zinc-900 hover:bg-zinc-800 text-white px-4 py-2 rounded-xl text-xs font-bold transition-all border border-zinc-800 active-press"
            >
              <BookOpen size={14} /> Presets <ChevronDown size={14} className={showPresets ? 'rotate-180' : ''} />
            </button>
            {showPresets && (
              <div className="absolute top-full right-0 mt-2 w-64 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-2xl z-50 overflow-hidden animate-scale-in glass-morphism">
                <div className="p-3 border-b border-zinc-800 text-[10px] font-black uppercase text-zinc-500 tracking-widest">Select Template</div>
                {SCRIPT_PRESETS.map(p => (
                  <button
                    key={p.id}
                    onClick={() => applyPreset(p)}
                    className="w-full text-left px-4 py-3 hover:bg-red-500/10 hover:text-white text-zinc-400 text-sm font-medium border-b border-zinc-800 last:border-0 transition-colors"
                  >
                    {p.label}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4 p-6 bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex-1 flex flex-col shadow-2xl">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Video Headline</label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="e.g. YouTube Automation Walkthrough"
              className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-red-500/50 outline-none transition-all text-white font-medium placeholder:text-zinc-800"
            />
          </div>

          <div className="space-y-2 flex-1 flex flex-col">
            <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block ml-1">Logic Constraints</label>
            <div className="flex-1 flex flex-col bg-zinc-950 border border-zinc-800 rounded-2xl overflow-hidden focus-within:ring-2 focus-within:ring-red-500/50 transition-all shadow-inner">
              <div className="flex items-center gap-1 p-2 border-b border-zinc-800 bg-zinc-900/40">
                <button type="button" onClick={() => insertFormat('**', '**')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <Bold size={14} />
                </button>
                <button type="button" onClick={() => insertFormat('*', '*')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <Italic size={14} />
                </button>
                <div className="w-px h-4 bg-zinc-800 mx-1"></div>
                <button type="button" onClick={() => insertFormat('# ')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <Heading1 size={14} />
                </button>
                <button type="button" onClick={() => insertFormat('- ')} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded transition-colors">
                  <List size={14} />
                </button>
              </div>

              <textarea
                ref={instructionsRef}
                value={instructions}
                onChange={(e) => setInstructions(e.target.value)}
                placeholder="Describe narrative flow, visual cues, and key takeaways..."
                className="w-full h-full min-h-[120px] bg-transparent p-5 outline-none resize-none text-white text-sm leading-relaxed placeholder:text-zinc-800"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Structural Tier</label>
              <select
                value={scriptType}
                onChange={(e) => setScriptType(e.target.value)}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500/50 outline-none text-white appearance-none text-[10px] font-black uppercase tracking-widest cursor-pointer"
              >
                <option value="standard">Standard YouTube</option>
                <option value="storytelling">Storytelling / Docu</option>
                <option value="tutorial">How-To Tutorial</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Acoustic Tone</label>
              <select
                value={tone}
                onChange={(e) => setTone(e.target.value)}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-red-500/50 outline-none text-white appearance-none text-[10px] font-black uppercase tracking-widest cursor-pointer"
              >
                <option>Engaging & Fun</option>
                <option>Professional</option>
                <option>Fast-paced & Hype</option>
                <option>Deep Dive</option>
              </select>
            </div>
          </div>

          <button
            type="submit"
            disabled={isGenerating || !title}
            className={`w-full py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-widest flex items-center justify-center gap-3 transition-all active-press ${
              isGenerating 
                ? 'bg-zinc-800 text-zinc-600' 
                : 'bg-red-600 hover:bg-red-500 text-white shadow-xl shadow-red-600/20'
            }`}
          >
            {isGenerating ? <Loader2 className="animate-spin" size={18} /> : <><Zap size={18} fill="currentColor" /> Synthesize Script</>}
          </button>
        </form>

        {/* Script Library Panel */}
        <div className="bg-zinc-900 border border-zinc-800 p-6 rounded-[2.5rem] shadow-xl overflow-hidden flex flex-col max-h-[300px]">
           <div className="flex items-center justify-between mb-4 shrink-0">
              <h3 className="text-[10px] font-black text-zinc-600 uppercase tracking-widest flex items-center gap-2">
                <History size={14} /> Script Library
              </h3>
              <span className="text-[9px] font-bold text-zinc-700 bg-zinc-950 px-2 py-0.5 rounded-full border border-zinc-800">{library.length} SAVED</span>
           </div>
           <div className="space-y-2 overflow-y-auto pr-2 custom-scrollbar">
              {library.map((item, i) => (
                <button 
                  key={i}
                  onClick={() => { setTitle(item.title); setScript(item.content); }}
                  className="w-full text-left p-3 rounded-xl bg-zinc-950 border border-zinc-800 hover:border-red-500/30 transition-all group"
                >
                   <div className="flex justify-between items-start gap-2 mb-1">
                      <p className="text-xs font-bold text-zinc-300 truncate group-hover:text-white transition-colors">{item.title}</p>
                      <Clock size={10} className="text-zinc-700 shrink-0 mt-0.5" />
                   </div>
                   <p className="text-[9px] text-zinc-600 font-medium uppercase tracking-tighter">Cached Archive</p>
                </button>
              ))}
           </div>
        </div>
      </div>

      {/* Editor/Preview Panel */}
      <div className="flex-1 flex flex-col bg-zinc-900 border border-zinc-800 rounded-[3rem] overflow-hidden shadow-2xl relative">
        <div className="p-6 border-b border-zinc-800 flex justify-between items-center bg-zinc-950/50 backdrop-blur-md">
          <div className="flex items-center gap-3">
             <div className="w-2 h-2 rounded-full bg-red-600 animate-pulse shadow-[0_0_10px_rgba(239,68,68,0.5)]"></div>
             <span className="text-[10px] font-black uppercase tracking-widest text-zinc-500">Live Narrative Manifest</span>
          </div>
          <div className="flex gap-2">
            {script && (
               <button 
                 onClick={() => { navigator.clipboard.writeText(script); alert("Script copied!"); }}
                 className="flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-zinc-800 hover:bg-zinc-700 text-white px-4 py-2 rounded-xl transition-all border border-zinc-700"
               >
                 <Copy size={12} /> Copy
               </button>
            )}
            {script && !isGenerating && (
               <button 
                 onClick={handleDownload}
                 className="flex items-center gap-2 text-[10px] font-black uppercase tracking-tighter bg-white hover:bg-zinc-200 text-black px-4 py-2 rounded-xl transition-all shadow-lg active-press"
               >
                 <Download size={12} /> Export .MD
               </button>
            )}
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-12 bg-[#09090b] custom-scrollbar selection:bg-red-500/30">
           {script ? (
             <div className="max-w-3xl mx-auto">
                <pre className="whitespace-pre-wrap font-sans text-xl md:text-2xl font-bold leading-relaxed text-zinc-100 tracking-tight">
                  {script}
                </pre>
                <div ref={scriptEndRef} />
             </div>
           ) : (
             <div className="h-full flex flex-col items-center justify-center text-zinc-800 gap-8 opacity-30 animate-pulse">
                <div className="w-40 h-40 rounded-[3rem] border-4 border-dashed border-zinc-800 flex items-center justify-center">
                   <FileText size={80} strokeWidth={1} />
                </div>
                <div className="text-center space-y-2">
                   <p className="font-black uppercase tracking-[0.4em] text-sm">Workspace Dormant</p>
                   <p className="text-[10px] font-bold tracking-widest uppercase opacity-60">Awaiting semantic input</p>
                </div>
             </div>
           )}
        </div>

        {/* Bottom Fade Gradient */}
        <div className="absolute bottom-0 left-0 right-0 h-32 bg-gradient-to-t from-[#09090b] to-transparent pointer-events-none"></div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { generateVideo, generateSpeech } from '../services/gemini';
import { 
  Loader2, 
  Video as VideoIcon, 
  Upload, 
  PlayCircle, 
  Download, 
  Scissors, 
  Mic, 
  Layers, 
  Plus, 
  Trash2, 
  PauseCircle, 
  SkipBack, 
  SkipForward, 
  Wand2, 
  Volume2, 
  Film, 
  Zap, 
  Save, 
  Check,
  X,
  AudioLines,
  Sparkles,
  Monitor,
  Key,
  RotateCcw,
  Gauge,
  Clock
} from 'lucide-react';

const LOADING_MESSAGES = [
  "Initializing Veo creative engine...",
  "Analyzing visual descriptors and style cues...",
  "Synthesizing high-fidelity frames...",
  "Applying temporal coherence and physics...",
  "Finalizing cinematic render...",
  "Optimizing for your target aspect ratio...",
  "Hang tight, artistic perfection takes a moment..."
];

const SPEED_OPTIONS = [0.5, 0.75, 1, 1.25, 1.5, 2];

interface TimelineClip {
  id: string;
  type: 'video' | 'audio';
  url: string;
  name: string;
  duration: number;
  trimStart: number;
  trimEnd: number;
  timelineOffset: number;
  playbackSpeed: number;
}

export const VideoStudio: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'create' | 'edit'>('create');
  const [hasApiKey, setHasApiKey] = useState(true);

  // --- GENERATOR STATE ---
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [resolution, setResolution] = useState<'720p' | '1080p'>('1080p');
  const [startImage, setStartImage] = useState<string | null>(null);
  const [generatedVideoUrl, setGeneratedVideoUrl] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [loadingMsgIndex, setLoadingMsgIndex] = useState(0);
  const [justAdded, setJustAdded] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- EDITOR STATE ---
  const [timeline, setTimeline] = useState<TimelineClip[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [totalDuration, setTotalDuration] = useState(0);

  const previewVideoRef = useRef<HTMLVideoElement>(null);
  const editorFileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(selected);
      }
    };
    checkKey();
  }, []);

  useEffect(() => {
    let interval: any;
    if (isGenerating) {
      interval = setInterval(() => {
        setLoadingMsgIndex(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 5000);
    }
    return () => clearInterval(interval);
  }, [isGenerating]);

  const handleOpenKeyPicker = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey && window.aistudio) {
       await handleOpenKeyPicker();
    }

    setIsGenerating(true);
    setGeneratedVideoUrl(null);
    try {
      const url = await generateVideo(prompt, aspectRatio, startImage || undefined, resolution);
      if (url) {
        setGeneratedVideoUrl(url);
      }
    } catch (error: any) {
      console.error(error);
      if (error.message?.includes("Requested entity was not found")) {
         setHasApiKey(false);
         alert("Project mismatch or missing API key. Please select your paid API key again.");
      } else {
         alert("Video generation failed. Please try a different prompt.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setStartImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const sendToEditor = () => {
    if (generatedVideoUrl) {
      addVideoToTimeline(generatedVideoUrl, `AI Clip ${timeline.length + 1}`);
      setJustAdded(true);
      setTimeout(() => {
        setJustAdded(false);
        setActiveTab('edit');
      }, 800);
    }
  };

  const addVideoToTimeline = (url: string, name: string) => {
    const tempVid = document.createElement('video');
    tempVid.src = url;
    tempVid.onloadedmetadata = () => {
      const duration = tempVid.duration || 10;

      setTimeline(prev => {
        // Calculate next offset based on the most recent state
        let nextOffset = 0;
        if (prev.length > 0) {
          const last = prev[prev.length - 1];
          nextOffset = last.timelineOffset + (last.trimEnd - last.trimStart) / last.playbackSpeed;
        }

        const newClip: TimelineClip = {
          id: Math.random().toString(36).substring(2, 11),
          type: 'video',
          url,
          name,
          duration,
          trimStart: 0,
          trimEnd: duration,
          timelineOffset: nextOffset,
          playbackSpeed: 1
        };

        const newTimeline = [...prev, newClip];
        recalculateTotalDuration(newTimeline);
        return newTimeline;
      });
    };
  };

  const recalculateTotalDuration = (clips: TimelineClip[]) => {
    let max = 0;
    clips.forEach(c => {
      const end = c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed;
      if (end > max) max = end;
    });
    setTotalDuration(max);
  };

  const clearTimeline = () => {
    if (confirm("Clear all clips from the current timeline?")) {
      setTimeline([]);
      setTotalDuration(0);
      setCurrentTime(0);
      setIsPlaying(false);
    }
  };

  const togglePlay = () => setIsPlaying(!isPlaying);

  const seek = (time: number) => {
    setCurrentTime(Math.max(0, Math.min(time, totalDuration)));
  };

  useEffect(() => {
    let animationFrameId: number;
    if (isPlaying) {
      const startTime = performance.now();
      const initialCurrentTime = currentTime;
      const animate = (now: number) => {
        const delta = (now - startTime) / 1000;
        const next = initialCurrentTime + delta;
        if (next >= totalDuration) {
          setIsPlaying(false);
          setCurrentTime(totalDuration);
        } else {
          setCurrentTime(next);
          animationFrameId = requestAnimationFrame(animate);
        }
      };
      animationFrameId = requestAnimationFrame(animate);
    }
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPlaying, totalDuration]);

  // Sync Video Ref with currentTime
  useEffect(() => {
    if (previewVideoRef.current) {
       const activeClip = timeline.find(c => 
         c.type === 'video' && 
         currentTime >= c.timelineOffset && 
         currentTime <= (c.timelineOffset + (c.trimEnd - c.trimStart) / c.playbackSpeed)
       );
       if (activeClip) {
          if (previewVideoRef.current.src !== activeClip.url) {
            previewVideoRef.current.src = activeClip.url;
          }

          // Apply speed to the HTML video element
          previewVideoRef.current.playbackRate = activeClip.playbackSpeed;

          const internalTime = activeClip.trimStart + (currentTime - activeClip.timelineOffset) * activeClip.playbackSpeed;
          if (Math.abs(previewVideoRef.current.currentTime - internalTime) > 0.2) {
             previewVideoRef.current.currentTime = internalTime;
          }
       }
    }
  }, [currentTime, timeline]);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in">
      <header className="flex items-center justify-between py-6 border-b border-zinc-800 shrink-0 mb-6">
        <div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight">Video Production</h2>
          <p className="text-zinc-400 text-sm">Create cinematic AI clips and orchestrate your timeline.</p>
        </div>
        <div className="flex gap-4 items-center">
          {!hasApiKey && (
             <button 
               onClick={handleOpenKeyPicker}
               className="flex items-center gap-2 bg-yellow-500/10 border border-yellow-500/30 text-yellow-500 px-4 py-2 rounded-xl text-xs font-bold animate-pulse"
             >
                <Key size={14} /> Connect API Key
             </button>
          )}
          <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800">
            <button 
              onClick={() => setActiveTab('create')}
              className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'create' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
            >
              Generation
            </button>
            <button 
              onClick={() => setActiveTab('edit')}
              className={`px-6 py-2 rounded-xl text-xs font-bold transition-all ${activeTab === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
            >
              Timeline
            </button>
          </div>
        </div>
      </header>

      {activeTab === 'create' ? (
        <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
          <div className="w-full md:w-[400px] flex flex-col gap-6 overflow-y-auto pr-2 custom-scrollbar">
            <form onSubmit={handleGenerate} className="bg-zinc-900 border border-zinc-800 p-8 rounded-[2.5rem] space-y-6 shadow-2xl">
              <div className="space-y-4">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Reference Frame (Optional)</label>
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-full h-44 border-2 border-dashed border-zinc-800 hover:border-red-500/50 rounded-3xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950/50 transition-all relative group overflow-hidden"
                >
                  {startImage ? (
                    <img src={startImage} alt="Reference" className="h-full w-full object-cover group-hover:scale-105 transition-transform" />
                  ) : (
                    <div className="text-zinc-600 flex flex-col items-center gap-2 group-hover:text-red-500 transition-colors">
                      <Upload size={32} />
                      <span className="text-[10px] font-black uppercase tracking-widest">Upload First Frame</span>
                    </div>
                  )}
                </div>
                <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
              </div>

              <div className="space-y-3">
                <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Action Sequence Prompt</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="e.g. A futuristic robot exploring a neon jungle, cinematic lighting, 4k, hyper-detailed..."
                  className="w-full h-40 bg-zinc-950 border border-zinc-800 rounded-2xl p-4 focus:ring-2 focus:ring-red-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Aspect Ratio</label>
                  <select 
                    value={aspectRatio}
                    onChange={(e) => setAspectRatio(e.target.value as any)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs text-white appearance-none cursor-pointer"
                  >
                    <option value="16:9">16:9 Landscape</option>
                    <option value="9:16">9:16 Portrait</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest">Output Quality</label>
                  <select 
                    value={resolution}
                    onChange={(e) => setResolution(e.target.value as any)}
                    className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs text-white appearance-none cursor-pointer"
                  >
                    <option value="1080p">1080p High Res</option>
                    <option value="720p">720p Standard</option>
                  </select>
                </div>
              </div>

              <button
                type="submit"
                disabled={isGenerating || (!prompt && !startImage)}
                className="w-full bg-red-600 hover:bg-red-500 disabled:opacity-50 text-white py-5 rounded-[1.5rem] font-black uppercase text-xs tracking-widest transition-all shadow-xl shadow-red-600/20 flex items-center justify-center gap-3 active-press"
              >
                {isGenerating ? <Loader2 className="animate-spin" size={20} /> : <><Sparkles size={18} /> Generate Clip</>}
              </button>
            </form>

            <div className="p-6 bg-zinc-900/50 border border-zinc-800 rounded-[2rem] flex items-start gap-4">
               <div className="p-3 bg-blue-500/10 rounded-2xl text-blue-400">
                  <Zap size={20} />
               </div>
               <div>
                  <h4 className="text-[10px] font-bold text-white uppercase tracking-widest mb-1">Veo Pro Tip</h4>
                  <p className="text-[11px] text-zinc-500 leading-relaxed italic">
                    "Describe lighting and camera movement like 'tracking shot' or 'low angle' to get more cinematic results from the model."
                  </p>
               </div>
            </div>
          </div>

          <div className="flex-1 bg-zinc-950 rounded-[3rem] border border-zinc-800/50 flex items-center justify-center relative overflow-hidden group shadow-inner">
            {isGenerating ? (
              <div className="flex flex-col items-center gap-8 text-red-500 animate-fade-in">
                  <div className="relative">
                     <Loader2 className="animate-spin w-20 h-20" strokeWidth={1} />
                     <div className="absolute inset-0 bg-red-500 blur-3xl opacity-10 animate-pulse"></div>
                  </div>
                  <div className="text-center space-y-3">
                     <p className="text-xl font-black text-white tracking-tight animate-pulse uppercase">Dreaming your Vision</p>
                     <p className="text-xs text-zinc-500 font-medium max-w-[280px] mx-auto leading-relaxed">
                        {LOADING_MESSAGES[loadingMsgIndex]}
                     </p>
                  </div>
              </div>
            ) : generatedVideoUrl ? (
              <div className="w-full h-full flex flex-col animate-scale-in relative group">
                <video src={generatedVideoUrl} controls autoPlay loop className="w-full h-full object-contain bg-black shadow-2xl" />
                <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex gap-4 opacity-0 group-hover:opacity-100 transition-all duration-500 transform group-hover:translate-y-0 translate-y-4">
                    <button 
                      onClick={sendToEditor}
                      disabled={justAdded}
                      className={`px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 backdrop-blur-xl shadow-2xl transition-all active-press ${justAdded ? 'bg-green-600 text-white' : 'bg-white hover:bg-zinc-200 text-black'}`}
                    >
                       {justAdded ? <><Check size={18} /> Added to Tracks</> : <><Scissors size={18} /> Use in Timeline</>}
                    </button>
                    <a 
                      href={generatedVideoUrl} 
                      download={`ranktica_clip_${Date.now()}.mp4`}
                      className="bg-zinc-900/80 hover:bg-zinc-800 text-white px-8 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center gap-2 border border-zinc-700 shadow-2xl transition-all active-press"
                    >
                      <Download size={18} /> Download
                    </a>
                </div>
              </div>
            ) : (
              <div className="text-zinc-800 flex flex-col items-center gap-6 opacity-30 animate-pulse">
                  <div className="w-40 h-40 rounded-[2.5rem] border-4 border-dashed border-zinc-800 flex items-center justify-center">
                     <VideoIcon size={80} strokeWidth={1.5} />
                  </div>
                  <p className="font-black uppercase text-sm tracking-[0.4em]">Visualizer Ready</p>
              </div>
            )}
          </div>
        </div>
      ) : (
        <div className="flex-1 flex flex-col gap-6 overflow-hidden animate-fade-in">
           {/* Preview Panel */}
           <div className="flex-1 bg-black rounded-[3rem] relative flex items-center justify-center overflow-hidden border border-zinc-800 shadow-2xl">
              <video ref={previewVideoRef} className="max-h-full max-w-full" onEnded={() => setIsPlaying(false)} />

              {timeline.length === 0 && (
                <div className="text-zinc-900 flex flex-col items-center gap-4">
                   <Layers size={80} className="opacity-20" />
                   <p className="font-black uppercase tracking-[0.4em] text-xs opacity-40">Timeline Empty</p>
                </div>
              )}

              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-md border border-zinc-800/50 rounded-2xl px-6 py-3 flex items-center gap-6 shadow-2xl">
                 <div className="flex items-center gap-4">
                    <button onClick={() => seek(0)} className="p-2 text-zinc-500 hover:text-white transition-colors active-press"><SkipBack size={20} /></button>
                    <button onClick={togglePlay} className="p-3 bg-red-600 hover:bg-red-500 rounded-full text-white transition-all shadow-lg shadow-red-600/20 active-press">
                       {isPlaying ? <PauseCircle size={32} /> : <PlayCircle size={32} />}
                    </button>
                    <button onClick={() => seek(totalDuration)} className="p-2 text-zinc-500 hover:text-white transition-colors active-press"><SkipForward size={20} /></button>
                 </div>
                 <div className="w-px h-8 bg-zinc-800"></div>
                 <span className="text-sm font-mono text-zinc-300 min-w-[120px] text-center">
                    {currentTime.toFixed(2)}s / {totalDuration.toFixed(2)}s
                 </span>
              </div>
           </div>

           {/* Timeline Control Panel */}
           <div className="h-[45%] bg-zinc-900 border border-zinc-800 rounded-[2.5rem] flex flex-col overflow-hidden shadow-2xl">
              <div className="h-16 border-b border-zinc-800 flex items-center justify-between px-8 bg-zinc-950/50">
                 <h3 className="text-xs font-black uppercase tracking-widest text-zinc-400">Master Sequence</h3>
                 <div className="flex items-center gap-4">
                    <button 
                      onClick={clearTimeline}
                      className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2 text-zinc-500 hover:text-red-500 transition-colors px-4 py-2"
                    >
                      <RotateCcw size={14} /> Reset
                    </button>
                    <button 
                      onClick={() => editorFileInputRef.current?.click()}
                      className="text-[10px] font-black uppercase tracking-widest flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-white px-5 py-2.5 rounded-xl border border-zinc-700 transition-all active-press"
                    >
                      <Plus size={14} /> Import Media
                    </button>
                    <input type="file" ref={editorFileInputRef} onChange={(e) => {
                       const file = e.target.files?.[0];
                       if (file) addVideoToTimeline(URL.createObjectURL(file), file.name);
                    }} className="hidden" accept="video/*" />
                 </div>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-4 bg-black/20 custom-scrollbar">
                 {timeline.length === 0 ? (
                   <div className="h-full flex flex-col items-center justify-center text-zinc-800">
                      <p className="text-sm font-bold uppercase tracking-widest opacity-30 italic">No tracks detected in current workspace</p>
                   </div>
                 ) : (
                   timeline.map((clip) => (
                     <div key={clip.id} className="group relative bg-zinc-900 border border-zinc-800/60 rounded-[2rem] p-5 flex gap-6 items-center hover:border-zinc-700 transition-all hover:shadow-xl">
                        <div className={`p-5 rounded-2xl shrink-0 transition-transform duration-500 group-hover:rotate-6 ${clip.type === 'video' ? 'bg-blue-600/10 text-blue-500 shadow-inner' : 'bg-purple-600/10 text-purple-500 shadow-inner'}`}>
                           {clip.type === 'video' ? <Film size={28} strokeWidth={1.5} /> : <AudioLines size={28} strokeWidth={1.5} />}
                        </div>

                        <div className="flex-1 min-w-0 space-y-4">
                           <div className="flex justify-between items-start">
                              <div className="min-w-0">
                                 <h4 className="text-base font-extrabold text-white truncate group-hover:text-red-500 transition-colors">{clip.name}</h4>
                                 <p className="text-[9px] text-zinc-500 uppercase font-black tracking-[0.2em] mt-1">{clip.type} source · {clip.duration.toFixed(1)}s total</p>
                              </div>
                              <button 
                                onClick={() => {
                                   const updated = timeline.filter(c => c.id !== clip.id);
                                   setTimeline(updated);
                                   recalculateTotalDuration(updated);
                                }} 
                                className="p-2.5 text-zinc-600 hover:text-red-500 transition-all bg-zinc-950 rounded-xl border border-zinc-800 active-press"
                              >
                                 <Trash2 size={16} />
                              </button>
                           </div>

                           <div className="grid grid-cols-2 md:grid-cols-4 gap-4 items-end">
                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1">Offset (s)</span>
                                 <div className="bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2">
                                    <input 
                                      type="number" 
                                      value={clip.timelineOffset} 
                                      step={0.1}
                                      onChange={(e) => {
                                        const val = parseFloat(e.target.value) || 0;
                                        setTimeline(prev => {
                                          const next = prev.map(c => c.id === clip.id ? { ...c, timelineOffset: val } : c);
                                          recalculateTotalDuration(next);
                                          return next;
                                        });
                                      }}
                                      className="bg-transparent border-none outline-none text-xs font-bold text-white w-full" 
                                    />
                                 </div>
                              </div>

                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1 flex items-center gap-1">
                                   <Gauge size={10} /> Speed
                                 </span>
                                 <div className="relative">
                                    <select 
                                         value={clip.playbackSpeed} 
                                         onChange={(e) => {
                                           const val = parseFloat(e.target.value) || 1;
                                           setTimeline(prev => {
                                             const next = prev.map(c => c.id === clip.id ? { ...c, playbackSpeed: val } : c);
                                             recalculateTotalDuration(next);
                                             return next;
                                           });
                                         }}
                                         className="w-full bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2 text-xs font-bold text-white appearance-none cursor-pointer focus:border-red-500 transition-colors"
                                    >
                                          {SPEED_OPTIONS.map(s => <option key={s} value={s}>{s}x</option>)}
                                    </select>
                                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-600">
                                       <Zap size={10} fill="currentColor" />
                                    </div>
                                 </div>
                              </div>

                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1 flex items-center gap-1">
                                   <Scissors size={10} /> Trim Start (s)
                                 </span>
                                 <div className="bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2">
                                    <input 
                                      type="number" 
                                      value={clip.trimStart} 
                                      step={0.1}
                                      min={0}
                                      max={clip.trimEnd}
                                      onChange={(e) => {
                                        const val = Math.max(0, Math.min(parseFloat(e.target.value) || 0, clip.trimEnd));
                                        setTimeline(prev => {
                                          const next = prev.map(c => c.id === clip.id ? { ...c, trimStart: val } : c);
                                          recalculateTotalDuration(next);
                                          return next;
                                        });
                                      }}
                                      className="bg-transparent border-none outline-none text-xs font-bold text-white w-full" 
                                    />
                                 </div>
                              </div>

                              <div className="space-y-1.5">
                                 <span className="text-[9px] font-black text-zinc-600 uppercase tracking-widest ml-1 flex items-center gap-1">
                                   <Scissors size={10} /> Trim End (s)
                                 </span>
                                 <div className="bg-zinc-950 border border-zinc-800 rounded-xl px-3 py-2">
                                    <input 
                                      type="number" 
                                      value={clip.trimEnd} 
                                      step={0.1}
                                      min={clip.trimStart}
                                      max={clip.duration}
                                      onChange={(e) => {
                                        const val = Math.max(clip.trimStart, Math.min(parseFloat(e.target.value) || clip.duration, clip.duration));
                                        setTimeline(prev => {
                                          const next = prev.map(c => c.id === clip.id ? { ...c, trimEnd: val } : c);
                                          recalculateTotalDuration(next);
                                          return next;
                                        });
                                      }}
                                      className="bg-transparent border-none outline-none text-xs font-bold text-white w-full" 
                                    />
                                 </div>
                              </div>
                           </div>

                           <div className="mt-4 space-y-2">
                              <div className="flex justify-between text-[9px] font-black text-zinc-700 uppercase tracking-widest">
                                 <span className="flex items-center gap-1"><Clock size={10} /> Actual Playtime</span>
                                 <span className="text-zinc-500 font-bold">{((clip.trimEnd - clip.trimStart) / clip.playbackSpeed).toFixed(1)}s runtime</span>
                              </div>
                              <div className="h-2 w-full bg-zinc-950 rounded-full overflow-hidden relative border border-zinc-800/50 shadow-inner">
                                 {/* Full Duration Shadow */}
                                 <div className="absolute inset-0 bg-zinc-900 opacity-30"></div>
                                 {/* Trimmed Duration Bar */}
                                 <div 
                                   className={`absolute top-0 bottom-0 ${clip.type === 'video' ? 'bg-red-600' : 'bg-blue-600'} transition-all duration-300 shadow-[0_0_10px_rgba(239,68,68,0.3)] rounded-full`} 
                                   style={{ 
                                     left: `${(clip.trimStart / clip.duration) * 100}%`, 
                                     width: `${((clip.trimEnd - clip.trimStart) / clip.duration) * 100}%` 
                                   }}
                                 ></div>
                              </div>
                           </div>
                        </div>
                     </div>
                   ))
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
