];

const LIGHTING_OPTS = ['Cinematic Rim', 'Neon Glow', 'Golden Hour', 'High-Key Studio', 'Chiaroscuro', 'Volumetric Rays', 'Global Illumination', 'Hard Spotlight'];
const ANGLE_OPTS = ['Low Angle Heroic', 'Extreme Close-up', 'Bird\'s Eye View', 'Macro Detail', 'POV Perspective', 'Wide Dynamic', 'Dutch Angle', 'Flat Lay'];
const TEXTURE_OPTS = ['Weathered/Grit', 'Glossy Iridescent', 'Matte Finish', 'Metallic/Chrome', 'Organic/Raw', 'Hyper-Realistic', 'Brushed Metal', 'Matte Plastic'];
const ATMOSPHERE_OPTS = ['Suspenseful', 'High Energy', 'Dreamy', 'Industrial', 'Ethereal', 'Aggressive', 'Nostalgic', 'Muted/Somber'];
const COMPOSITION_OPTS = ['Rule of Thirds', 'Golden Ratio', 'Symmetry', 'Deep Depth of Field', 'Leading Lines', 'Center Focused', 'Framed', 'Unconventional'];

const ASPECT_RATIOS = [
  { id: '16:9', label: 'YouTube Standard', icon: <Monitor size={18} /> },
  { id: '9:16', label: 'Shorts / TikTok', icon: <Smartphone size={18} /> },
  { id: '1:1', label: 'Community', icon: <Square size={18} /> }
];

const SIZES = ['1K', '2K', '4K'];

export const ThumbnailGenerator: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [genMode, setGenMode] = useState<'fast' | 'pro' | 'artistic'>('fast');
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('Photorealistic');
  const [aspectRatio, setAspectRatio] = useState('16:9');
  const [imageSize, setImageSize] = useState('1K');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Visual Modifiers
  const [lighting, setLighting] = useState('');
  const [angle, setAngle] = useState('');
  const [texture, setTexture] = useState('');
  const [atmosphere, setAtmosphere] = useState('');
  const [composition, setComposition] = useState('');

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const { incrementStat } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Computed final prompt for preview
  const [builtPrompt, setBuiltPrompt] = useState('');

  useEffect(() => {
    const modifiers = [
      atmosphere && `atmosphere: ${atmosphere}`,
      composition && `composition: ${composition}`,
      lighting && `lighting: ${lighting}`,
      angle && `angle: ${angle}`,
      texture && `texture: ${texture}`
    ].filter(Boolean).join(', ');

    const final = modifiers ? `${prompt}. [Parameters: style=${style}, ${modifiers}]` : prompt;
    setBuiltPrompt(final);
  }, [prompt, style, lighting, angle, texture, atmosphere, composition]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(builtPrompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
      if (!err.message?.includes("API key")) {
        alert("Generation failed. Please try a different prompt or style.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleEnhance = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      // Pass a more descriptive goal to the enhancer
      const contextPrompt = `Enhance the following prompt to be highly descriptive for a high-end AI image generator. Include specific mentions of materials, lighting physics (like raytracing), and cinematic camera details: "${prompt}"`;
      const enhanced = await enhanceThumbnailPrompt(contextPrompt);
      setPrompt(enhanced);
    } catch (e) {
      console.error(e);
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

