             {/* Architect Modifiers */}
             {mode === 'generate' && (
               <div className="space-y-8 pt-2">
                  <ModifierGroup 
                    label="Atmospheric Mood" 
                    icon={Wind} 
                    options={ATMOSPHERE_OPTS} 
