                   <div className="w-24 h-24 rounded-full border-4 border-zinc-800 flex items-center justify-center">
                      <Loader2 className="animate-spin w-10 h-10" />
                   </div>
                   <div className="absolute inset-0 bg-orange-500 blur-3xl opacity-20 animate-pulse"></div>
                </div>
                <div className="text-center space-y-2">
                   <p className="text-xl font-black text-white tracking-tight animate-pulse uppercase">Casting Pixels</p>
                   <p className="text-xs text-zinc-500 font-medium tracking-widest uppercase">Consulting {genMode.toUpperCase()} Tensor Core</p>
