           ) : resultImage ? (
             <div className="w-full h-full flex flex-col animate-scale-in">
               <img src={resultImage} alt="Result" className="w-full h-full object-contain bg-black shadow-2xl" />

               <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-4 opacity-0 group-hover:opacity-100 transition-all duration-500 transform group-hover:translate-y-0 translate-y-4">
                  <button 
                    onClick={() => {
                      setUploadedImage(resultImage);
                      setMode('edit');
