export const ThumbnailGenerator: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [genMode, setGenMode] = useState<'fast' | 'pro' | 'artistic'>('fast');
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('Photorealistic');
  const [aspectRatio, setAspectRatio] = useState('16:9');
  const [imageSize, setImageSize] = useState('1K');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Visual Modifiers
  const [lighting, setLighting] = useState('');
  const [optics, setOptics] = useState('');
  const [texture, setTexture] = useState('');
  const [mood, setMood] = useState('');
  const [composition, setComposition] = useState('');

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const { incrementStat } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Computed final prompt for preview
  const [builtPrompt, setBuiltPrompt] = useState('');

  useEffect(() => {
    if (!prompt) {
      setBuiltPrompt('');
      return;
    }

    // Build a narrative descriptive prompt
    const parts = [];
    parts.push(`A ${style.toLowerCase()} style YouTube thumbnail of ${prompt}`);

    if (composition) parts.push(`utilizing a ${composition.toLowerCase()} composition`);
    if (optics) parts.push(`captured with a ${optics.toLowerCase()}`);
    if (lighting) parts.push(`illuminated by ${lighting.toLowerCase()}`);
    if (mood) parts.push(`creating a ${mood.toLowerCase()} atmosphere`);
    if (texture) parts.push(`featuring ${texture.toLowerCase()} for hyper-realistic detail`);

    parts.push(`High fidelity, maximum contrast, click-worthy, 8k resolution.`);

    const final = parts.join('. ') + '.';
    setBuiltPrompt(final);
  }, [prompt, style, lighting, optics, texture, mood, composition]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(builtPrompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
      if (!err.message?.includes("API key")) {
        alert("Generation failed. Please try a different prompt or style.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleEnhance = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      const contextPrompt = `Enhance the following prompt to be highly descriptive for a high-end AI image generator. Focus on lighting physics (raytracing, bounce light), complex materials, and specific cinematic optics. Target a professional content creator aesthetic: "${prompt}"`;
      const enhanced = await enhanceThumbnailPrompt(contextPrompt);
      setPrompt(enhanced);
    } catch (e) {
      console.error(e);
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const ModifierGroup = ({ label, icon: Icon, options, current, setter, color }: any) => (
    <div className="space-y-3">
      <label className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${color}`}>
         <Icon size={12} /> {label}
      </label>
      <div className="flex flex-wrap gap-2">
         {options.map((opt: string) => (
           <button
             key={opt}
             type="button"
             onClick={() => setter(current === opt ? '' : opt)}
             className={`px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase transition-all border ${current === opt ? 'bg-zinc-100 border-white text-black shadow-lg scale-105' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
           >
             {opt}
           </button>
         ))}
      </div>
    </div>
  );

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
             <ImageIcon className="text-orange-500" /> Thumbnail Studio
          </h2>
          <p className="text-zinc-400 text-sm font-medium">Professional High-CTR Visual Architecture</p>
        </div>

        <div className="flex bg-zinc-900/50 rounded-2xl p-1 border border-zinc-800 self-start md:self-center">
          <button 
            onClick={() => setMode('generate')}
            className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === 'generate' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
          >
            Concept Studio
          </button>
          <button 
            onClick={() => setMode('edit')}
            className={`px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${mode === 'edit' ? 'bg-zinc-800 text-white shadow-lg' : 'text-zinc-500 hover:text-white'}`}
          >
            Neural Edit
          </button>
        </div>
      </header>

      <div className="flex-1 flex flex-col md:flex-row gap-8 min-h-0">
        {/* LEFT PANEL: CONFIG */}
        <div className="w-full md:w-[450px] flex flex-col gap-6 overflow-y-auto pr-3 custom-scrollbar pb-10">

          <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] p-8 space-y-8 shadow-2xl relative overflow-hidden">
             {/* Engine Selection */}
             {mode === 'generate' && (
               <div className="space-y-4">
                  <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Inference Engine</label>
                  <div className="grid grid-cols-3 gap-2">
                    {[
                      { id: 'fast', label: 'Flash Core', color: 'blue' },
                      { id: 'pro', label: 'Pro Vision', color: 'orange' },
                      { id: 'artistic', label: 'Imagen 4.0', color: 'purple' }
                    ].map(m => (
                      <button
                        key={m.id}
                        type="button"
                        onClick={() => setGenMode(m.id as any)}
                        className={`py-2 rounded-xl text-[10px] font-black uppercase border transition-all ${genMode === m.id ? `bg-${m.color}-500/10 border-${m.color}-500 text-${m.color}-500 shadow-lg` : 'bg-zinc-950 border-zinc-800 text-zinc-600 hover:border-zinc-700'}`}
                      >
                        {m.label}
                      </button>
                    ))}
                  </div>
               </div>
             )}

             {mode === 'edit' && (
               <div className="space-y-4">
                 <label className="text-[10px] font-black text-zinc-600 uppercase tracking-widest block">Latent Reference</label>
                 <div 
                   onClick={() => fileInputRef.current?.click()}
                   className="w-full h-44 border-2 border-dashed border-zinc-800 hover:border-orange-500/50 rounded-3xl flex flex-col items-center justify-center cursor-pointer bg-zinc-950/50 transition-all relative group overflow-hidden"
                 >
                   {uploadedImage ? (
                     <img src={uploadedImage} alt="Upload" className="h-full w-full object-contain p-4 group-hover:scale-105 transition-transform" />
