        disabled={!!limit && items.length >= limit}
        className={`p-1.5 rounded-lg transition-all ${
          limit && items.length >= limit 
            ? 'text-zinc-800 cursor-not-allowed' 
            : 'text-zinc-500 hover:text-white hover:bg-zinc-800'
