export const ThumbnailGenerator: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [genMode, setGenMode] = useState<'fast' | 'pro' | 'artistic'>('fast');
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('Photorealistic');
  const [aspectRatio, setAspectRatio] = useState('16:9');
  const [imageSize, setImageSize] = useState('1K');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Visual Modifiers
  const [lighting, setLighting] = useState('');
  const [optics, setOptics] = useState('');
  const [texture, setTexture] = useState('');
  const [mood, setMood] = useState('');
  const [composition, setComposition] = useState('');

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const { incrementStat } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Computed final prompt for preview
  const [builtPrompt, setBuiltPrompt] = useState('');

  useEffect(() => {
    if (!prompt) {
      setBuiltPrompt('');
      return;
    }

    // Build a narrative descriptive prompt focusing on physics and composition
    const parts = [];
    parts.push(`A masterfully crafted ${style.toLowerCase()} YouTube thumbnail depicting ${prompt}`);

    if (composition) parts.push(`using a professional ${composition.toLowerCase()} layout`);
    if (optics) parts.push(`captured with advanced ${optics.toLowerCase()} for depth`);
    if (lighting) parts.push(`meticulously lit with ${lighting.toLowerCase()}`);
    if (mood) parts.push(`evoking a ${mood.toLowerCase()} aesthetic`);
    if (texture) parts.push(`rendered with ${texture.toLowerCase()} for hyper-realistic materiality`);

    parts.push(`Incredible detail, 10-bit color depth, maximum visual impact, professional grading, unreal engine 5 style render, 8k resolution.`);

    const final = parts.join('. ') + '.';
    setBuiltPrompt(final);
  }, [prompt, style, lighting, optics, texture, mood, composition]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(builtPrompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
      if (!err.message?.includes("API key")) {
        alert("Generation failed. Please try a different prompt or style.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleEnhance = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      // Specialized instruction for high-end cinematic quality
      const contextPrompt = `Expand and enhance the following thumbnail concept into a highly detailed technical prompt. 
      Focus heavily on:
      1. Lighting Physics: Specify ray-tracing, bounce lighting, and volumetric shadows.
      2. Cinematic Optics: Describe specific focal lengths, lens distortions, and bokeh quality.
      3. Surface Materials: Detail textures like PBR materials, micro-imperfections, and displacement maps.
      4. Dynamic Composition: Use terms like Dutch angles, leading lines, or Rule of Thirds.
      Target a professional MKHBD/MrBeast level production quality. 
      Original Concept: "${prompt}"`;

      const enhanced = await enhanceThumbnailPrompt(contextPrompt);
      setPrompt(enhanced);
    } catch (e) {
      console.error(e);
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
