export const ThumbnailGenerator: React.FC = () => {
  const [mode, setMode] = useState<'generate' | 'edit'>('generate');
  const [genMode, setGenMode] = useState<'fast' | 'pro' | 'artistic'>('fast');
  const [prompt, setPrompt] = useState('');
  const [style, setStyle] = useState('Photorealistic');
  const [aspectRatio, setAspectRatio] = useState('16:9');
  const [imageSize, setImageSize] = useState('1K');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Visual Modifiers
  const [lighting, setLighting] = useState('');
  const [optics, setOptics] = useState('');
  const [texture, setTexture] = useState('');
  const [mood, setMood] = useState('');
  const [composition, setComposition] = useState('');
  const [colorGrade, setColorGrade] = useState('');

  const [resultImage, setResultImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [enhancing, setEnhancing] = useState(false);
  const { incrementStat } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Computed final prompt for preview
  const [builtPrompt, setBuiltPrompt] = useState('');

  useEffect(() => {
    if (!prompt) {
      setBuiltPrompt('');
      return;
    }

    // Build a narrative descriptive prompt focusing on physics, optics and material science
    const parts = [];
    parts.push(`A high-impact ${style.toLowerCase()} YouTube thumbnail masterpiece of ${prompt}`);

    if (composition) parts.push(`utilizing a ${composition.toLowerCase()}`);
    if (optics) parts.push(`captured via ${optics.toLowerCase()}`);
    if (lighting) parts.push(`illuminated by ${lighting.toLowerCase()}`);
    if (texture) parts.push(`featuring ${texture.toLowerCase()}`);
    if (colorGrade) parts.push(`color graded with ${colorGrade.toLowerCase()}`);
    if (mood) parts.push(`designed for a ${mood.toLowerCase()} vibe`);

    parts.push(`Ultra-high resolution, extreme sharp focus, cinematic lighting, 8k resolution, photorealistic textures, masterwork, award winning digital art.`);

    const final = parts.join('. ') + '.';
    setBuiltPrompt(final);
  }, [prompt, style, lighting, optics, texture, mood, composition, colorGrade]);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() && mode === 'generate') return;

    setLoading(true);
    setResultImage(null);

    try {
      let url;
      if (mode === 'generate') {
        url = await generateThumbnail(builtPrompt, style, genMode, aspectRatio, imageSize);
      } else {
        if (!uploadedImage) {
          alert("Please upload an image to edit.");
          setLoading(false);
          return;
        }
        url = await editImage(uploadedImage, prompt);
      }
      setResultImage(url);
      incrementStat('thumbnailsCreated');
    } catch (err: any) {
      console.error(err);
      if (!err.message?.includes("API key")) {
        alert("Generation failed. Please try a different prompt or style.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleEnhance = async () => {
    if (!prompt.trim()) return;
    setEnhancing(true);
    try {
      // Deeper specialized instruction for high-end cinematic quality
      const contextPrompt = `Refactor the following concept into a technical masterpiece prompt for a high-end AI generator (Gemini/Imagen). 
      Mandatory Focus:
      1. Optical Physics: Define specific focal length, f-stop, and lens flare artifacts.
      2. Lighting Science: Detail global illumination, bounce lighting, and spectral highlights.
      3. Material Science: Specify PBR textures, roughness maps, and anisotropic reflections.
      4. Dynamic Framing: Use terms like 'Hero Shot', 'Dutch Angle', or 'Vanishing Point'.
      Concept: "${prompt}"`;

      const enhanced = await enhanceThumbnailPrompt(contextPrompt);
      setPrompt(enhanced);
    } catch (e) {
      console.error(e);
    } finally {
      setEnhancing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const ModifierGroup = ({ label, icon: Icon, options, current, setter, color }: any) => (
    <div className="space-y-3">
      <label className={`text-[10px] font-black uppercase tracking-widest flex items-center gap-2 ${color}`}>
         <Icon size={12} /> {label}
      </label>
      <div className="flex flex-wrap gap-2">
         {options.map((opt: string) => (
           <button
             key={opt}
             type="button"
             onClick={() => setter(current === opt ? '' : opt)}
             className={`px-3 py-1.5 rounded-lg text-[9px] font-bold uppercase transition-all border ${current === opt ? 'bg-zinc-100 border-white text-black shadow-lg scale-105' : 'bg-zinc-950 border-zinc-800 text-zinc-500 hover:border-zinc-700'}`}
           >
             {opt}
           </button>
         ))}
      </div>
    </div>
  );

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in pb-4">
      <header className="flex flex-col md:flex-row md:items-center justify-between py-4 border-b border-zinc-800 shrink-0 mb-6 gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-white tracking-tight flex items-center gap-3">
             <ImageIcon className="text-orange-500" /> Thumbnail Studio
          </h2>
