export const generateIdeas = async (niche: string, count: number = 5): Promise<VideoIdea[]> => {
  const ai = getAiClient();
  const response = await ai.models.generateContent({
    model: MODEL_NAMES.TEXT_FAST,
    contents: `Generate ${count} viral ideas for: "${niche}".`,
    config: {
      systemInstruction: SYSTEM_INSTRUCTIONS.IDEAS,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: { title: { type: Type.STRING }, hook: { type: Type.STRING }, score: { type: Type.NUMBER } },
          required: ["title", "hook", "score"]
        }
      }
    }
  });
  const text = response.text;
  return text ? JSON.parse(text) : [];
};

