  Play,
  Monitor,
  Smartphone,
  Layout,
  Eye,
  ArrowRight
} from 'lucide-react';

const PSYCH_TRIGGERS = [
  { id: 'Curiosity', label: 'Curiosity Gap', desc: 'Create a "need to know" effect.' },
  { id: 'Urgency', label: 'Urgency', desc: 'Time-sensitive or FOMO-driven.' },
  { id: 'Negative', label: 'Negative Bias', desc: 'Warn against mistakes or pitfalls.' },
  { id: 'Listicle', label: 'Listicle', desc: 'Structured, numbered, and digestible.' },
  { id: 'How-To', label: 'Practical Value', desc: 'Direct solution to a problem.' },
  { id: 'Authority', label: 'Authority', desc: 'Leverage expert status or data.' },
  { id: 'Social Proof', label: 'Social Proof', desc: 'Focus on what "everyone" is doing.' }
];

export const TitleGenerator: React.FC = () => {
  const [context, setContext] = useState('');
  const [selectedTriggers, setSelectedTriggers] = useState<string[]>(['Curiosity', 'Listicle']);
  const [titles, setTitles] = useState<TitlePrediction[]>([]);
  const [loading, setLoading] = useState(false);
  const [copiedIdx, setCopiedIdx] = useState<number | null>(null);
  const [previewTitle, setPreviewTitle] = useState<string>('');

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!context.trim()) return;
    setLoading(true);
    setTitles([]);
    try {
      const results = await generateViralTitles(context, selectedTriggers);
      setTitles(results);
      if (results.length > 0) setPreviewTitle(results[0].title);
    } catch (e) {
      console.error(e);
      alert("Title generation failed.");
    } finally {
      setLoading(false);
    }
  };

  const toggleTrigger = (id: string) => {
    setSelectedTriggers(prev => 
      prev.includes(id) ? prev.filter(t => t !== id) : [...prev, id]
    );
  };

  const copyToClipboard = (text: string, idx: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIdx(idx);
    setTimeout(() => setCopiedIdx(null), 2000);
  };

  const getTriggerColor = (type: string) => {
    switch (type) {
      case 'Curiosity': return 'bg-purple-500/10 text-purple-400 border-purple-500/20';
      case 'Urgency': return 'bg-red-500/10 text-red-400 border-red-500/20';
      case 'Negative': return 'bg-orange-500/10 text-orange-400 border-orange-500/20';
      case 'Listicle': return 'bg-blue-500/10 text-blue-400 border-blue-500/20';
      case 'How-To': return 'bg-green-500/10 text-green-400 border-green-500/20';
      case 'Authority': return 'bg-zinc-500/10 text-zinc-400 border-zinc-500/20';
      case 'Social Proof': return 'bg-cyan-500/10 text-cyan-400 border-cyan-500/20';
      default: return 'bg-zinc-800 text-zinc-400';
    }
  };

  return (
    <div className="max-w-7xl mx-auto space-y-12 animate-fade-in pb-20">
      <div className="text-center space-y-4 py-8">
        <div className="inline-flex items-center justify-center p-4 rounded-[2rem] bg-red-500/10 text-red-500 mb-2 border border-red-500/20 shadow-2xl">
