          Engineer high-performance YouTube titles by stacking psychological triggers and predicting viral response.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Input Panel - 4 cols */}
        <div className="lg:col-span-4 space-y-6">
           <form onSubmit={handleGenerate} className="bg-zinc-900 border border-zinc-800 p-8 rounded-[2.5rem] shadow-2xl space-y-8">
              <div className="space-y-4">
                 <label className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] block ml-1">Video Context</label>
                 <textarea
                   value={context}
                   onChange={(e) => setContext(e.target.value)}
                   placeholder="Describe your video or current title (e.g. A tutorial on baking vegan sourdough bread)..."
                   className="w-full h-32 bg-zinc-950 border border-zinc-800 rounded-2xl p-5 focus:ring-2 focus:ring-red-500/50 outline-none transition-all resize-none text-white text-sm leading-relaxed"
                 />
              </div>

              <div className="space-y-4">
                 <div className="flex items-center justify-between">
                    <label className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.2em] block ml-1">Psychological Levers</label>
                    <span className="text-[9px] font-bold text-zinc-600 uppercase">{selectedTriggers.length} Active</span>
                 </div>
                 <div className="grid grid-cols-1 gap-2">
                    {PSYCH_TRIGGERS.map(t => (
                      <button
                        key={t.id}
                        type="button"
                        onClick={() => toggleTrigger(t.id)}
                        className={`text-left p-3 rounded-xl border transition-all relative overflow-hidden group ${
