                               className={`h-full transition-all duration-1000 delay-300 ${
                                  item.predictedCtr >= 12 ? 'bg-green-500' : 
                                  item.predictedCtr >= 8 ? 'bg-yellow-500' : 'bg-zinc-700'
                               }`}
                               style={{ width: `${Math.min(item.predictedCtr * 5, 100)}%` }}
                            />
                         </div>
                      </div>
                    ))}
                 </div>

                 {/* Disclaimer */}
                 <div className="p-6 bg-zinc-950 border-t border-zinc-800 flex items-center gap-3">
                    <AlertTriangle size={14} className="text-zinc-700" />
                    <p className="text-[9px] font-bold text-zinc-600 uppercase tracking-widest">
                       CTR predictions are estimates based on linguistic patterns. Simulation assumes a professional-grade thumbnail.
                    </p>
                 </div>
              </div>
           )}
        </div>
      </div>
    </div>
  );
};
